import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'success' | 'outline' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  fullWidth = false,
  className = '',
  ...props 
}) => {
  // Tesla Theme: Pill shaped, tracking wide, minimal glows
  const baseStyles = 'inline-flex items-center justify-center rounded-full font-medium transition-all duration-300 focus:outline-none disabled:opacity-50 disabled:cursor-not-allowed tracking-widest uppercase';

  const variants = {
    // High Contrast White (Primary Action)
    primary: 'bg-white text-zinc-950 hover:bg-zinc-200 hover:shadow-[0_0_20px_rgba(255,255,255,0.4)] border border-transparent',

    // Matte Dark (Secondary)
    secondary: 'bg-zinc-800 text-zinc-300 hover:bg-zinc-700 hover:text-white border border-zinc-700',

    // Danger Red (Alert/Stop)
    danger: 'bg-red-500/10 text-red-500 hover:bg-red-500 hover:text-white border border-red-500/50 hover:border-red-500 hover:shadow-[0_0_15px_rgba(239,68,68,0.4)]',

    // Success Cyan (Start/Active)
    success: 'bg-cyan-500/10 text-cyan-400 hover:bg-cyan-400 hover:text-zinc-950 border border-cyan-500/50 hover:border-cyan-400 hover:shadow-[0_0_15px_rgba(34,211,238,0.4)]',

    // Outline
    outline: 'border border-zinc-600 text-zinc-400 hover:border-white hover:text-white bg-transparent',

    // Ghost
    ghost: 'text-zinc-500 hover:text-white hover:bg-zinc-800'
  };

  const sizes = {
    sm: 'px-4 py-1.5 text-[10px] font-bold',
    md: 'px-6 py-2.5 text-xs font-bold',
    lg: 'px-8 py-4 text-sm font-bold'
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${fullWidth ? 'w-full' : ''} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

import React from 'react';

interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
  label?: string;
  error?: string;
}

export const Input: React.FC<InputProps> = ({ label, error, className = '', ...props }) => {
  return (
    <div className="w-full group">
      {label && <label className="block text-[10px] uppercase tracking-widest font-bold text-zinc-500 mb-2 group-hover:text-cyan-400 transition-colors">{label}</label>}
      <input
        className={`w-full bg-zinc-900/50 border-b border-zinc-700 text-white rounded-t px-4 py-3 text-sm placeholder-zinc-600 focus:outline-none focus:border-cyan-400 focus:bg-zinc-800/80 transition-all duration-300 font-mono ${error ? 'border-red-500 text-red-400' : ''} ${className}`}
        {...props}
      />
      {error && <p className="mt-1 text-[10px] text-red-500 font-bold uppercase tracking-wide">{error}</p>}
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { LayoutGrid, ScrollText, Database, Bluetooth, Cpu, ScanLine, Zap, Settings as SettingsIcon } from 'lucide-react';
import { bleService } from './services/bleService';
import { Controls } from './components/Controls';
import { InteractiveLog } from './components/InteractiveLog';
import { BatchResults } from './components/BatchResults';
import { WriterView } from './components/WriterView';
import { Button } from './components/ui/Button';
import { Logo } from './components/ui/Logo';
import { 
  ConnectionStatus, 
  ScanMode, 
  Tag, 
  Settings, 
  LogEntry,
  WriteStatus
} from './types';

type AppView = 'scanner' | 'writer' | 'settings';

function App() {
  // --- State ---
  const [activeView, setActiveView] = useState<AppView>('scanner');

  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [scanMode, setScanMode] = useState<ScanMode>(ScanMode.INTERACTIVE);
  const [isScanning, setIsScanning] = useState(false);

  // Mobile Tabs
  const [mobileTab, setMobileTab] = useState<'controls' | 'logs' | 'results'>('controls');

  // Settings
  const [settings, setSettings] = useState<Settings>({
    power: 30,
    frequency: 'US',
    rfParams: '1,4,1,0',
    buzzer: true,
    deviceInfo: ''
  });

  // Data
  const [tags, setTags] = useState<Tag[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [selectedEpc, setSelectedEpc] = useState('');

  // File Transfer
  const [fileContent, setFileContent] = useState<string>('');
  const [isTransferring, setIsTransferring] = useState(false);
  const [transferProgress, setTransferProgress] = useState(-1);

  // Write EPC State
  const [writeStatus, setWriteStatus] = useState<WriteStatus>('idle');
  const [writeMessage, setWriteMessage] = useState('');

  // --- Refs ---
  const tagBufferRef = useRef<Map<string, Tag>>(new Map());
  const lastRenderTimeRef = useRef(0);
  const animationFrameRef = useRef<number>(0);

  // --- Helpers ---
  const addLog = useCallback((message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [...prev.slice(-100), { type, message, timestamp: Date.now() }]);
  }, []);

  // --- BLE Logic ---
  const handleDataReceived = useCallback((data: any) => {
    if (data.cmd === 'live_tag' && data.epc) {
        const existing = tagBufferRef.current.get(data.epc);
        if (existing) {
            existing.count += 1;
            existing.rssi = data.rssi;
            tagBufferRef.current.set(data.epc, existing);
        } else {
            const newTag: Tag = { epc: data.epc, timestamp: Date.now(), rssi: data.rssi, count: 1 };
            tagBufferRef.current.set(data.epc, newTag);
        }
        return;
    }
    if (data.cmd === 'DI') { setSettings(prev => ({ ...prev, deviceInfo: data.val })); addLog(`Device Info: ${data.val}`, 'rx'); }
    if (data.cmd === 'GP') setSettings(prev => ({ ...prev, power: data.val }));
    if (data.cmd === 'GF') setSettings(prev => ({ ...prev, frequency: data.val }));
    if (data.cmd === 'GRP') setSettings(prev => ({ ...prev, rfParams: data.val }));
    if (data.cmd === 'BZ') setSettings(prev => ({ ...prev, buzzer: data.val === 'on' }));
    if (data.cmd === 'WE') {
      if (data.status === 'ok') { setWriteStatus('success'); setWriteMessage(`Encoded: ${data.epc}`); addLog(`Encode Success: ${data.epc}`, 'info'); } 
      else { setWriteStatus('error'); setWriteMessage('Encoding failed. Check log.'); addLog('Encode Failed.', 'error'); }
    }
  }, [addLog]);

  const handleFileEvent = useCallback((event: 'start' | 'progress' | 'complete' | 'error', data?: any) => {
    if (event === 'start') { setIsTransferring(true); setTransferProgress(0); setFileContent(''); addLog(`File transfer started...`, 'info'); } 
    else if (event === 'progress') { setTransferProgress(data); } 
    else if (event === 'complete') { setIsTransferring(false); setTransferProgress(100); setFileContent(data); addLog('Transfer complete.', 'info'); } 
    else if (event === 'error') { setIsTransferring(false); setTransferProgress(-1); addLog(`Transfer error: ${data}`, 'error'); }
  }, [addLog]);

  useEffect(() => {
    bleService.setCallbacks(handleDataReceived, (msg, type) => addLog(msg, type), handleFileEvent);
  }, [handleDataReceived, addLog, handleFileEvent]);

  useEffect(() => {
    const renderLoop = () => {
      const now = Date.now();
      if (now - lastRenderTimeRef.current > 150 && tagBufferRef.current.size > 0) {
        const allTags: Tag[] = Array.from(tagBufferRef.current.values());
        allTags.sort((a, b) => a.timestamp - b.timestamp);
        setTags(allTags.slice(0, 500));
        lastRenderTimeRef.current = now;
      }
      animationFrameRef.current = requestAnimationFrame(renderLoop);
    };
    animationFrameRef.current = requestAnimationFrame(renderLoop);
    return () => { if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current); };
  }, []);

  const handleConnect = async () => {
    try { setStatus(ConnectionStatus.CONNECTING); await bleService.connect(); setStatus(ConnectionStatus.CONNECTED); setTimeout(async () => { try { await bleService.getSettings(); } catch(e) {} }, 500); } catch (e) { setStatus(ConnectionStatus.ERROR); }
  };
  const handleDisconnect = () => { bleService.disconnect(); setStatus(ConnectionStatus.DISCONNECTED); setIsScanning(false); };
  const handleStartScan = async () => { if (status !== ConnectionStatus.CONNECTED) return; try { await bleService.sendCommand({ cmd: scanMode === ScanMode.INTERACTIVE ? 'S' : 'SB' }); setIsScanning(true); } catch (e: any) { addLog(e.message, 'error'); } };
  const handleStopScan = async () => { if (status !== ConnectionStatus.CONNECTED) return; try { await bleService.sendCommand({ cmd: scanMode === ScanMode.INTERACTIVE ? 'X' : 'XB' }); if (scanMode === ScanMode.BATCH) setTimeout(() => bleService.requestFileTransfer(), 500); setIsScanning(false); } catch (e: any) { addLog(e.message, 'error'); } };
  const handleRequestBatchFile = async () => { if (!isTransferring) { setFileContent(''); await bleService.requestFileTransfer(); } };
  const handleUpdateSettings = async (key: keyof Settings, value: string | number | boolean) => {
    setSettings(prev => ({ ...prev, [key]: value }));
    if (status !== ConnectionStatus.CONNECTED) return;
    let cmd = {};
    if (key === 'power') cmd = { cmd: 'SP', val: value };
    if (key === 'frequency') cmd = { cmd: 'SF', val: value };
    if (key === 'rfParams') cmd = { cmd: 'SRP', val: value };
    if (key === 'buzzer') cmd = { cmd: 'BZ', val: value ? 'on' : 'off' };
    await bleService.sendCommand(cmd);
  };
  const handleWriteEpc = async (oldEpc: string, newEpc: string) => { setWriteStatus('pending'); setWriteMessage(''); try { await bleService.sendCommand({ cmd: 'WE', old: oldEpc, new: newEpc }); } catch (e: any) { setWriteStatus('error'); setWriteMessage(e.message); } };
  const handleClearLog = () => { tagBufferRef.current.clear(); setTags([]); };

  const isConnected = status === ConnectionStatus.CONNECTED;

  // --- Brand Logo Component ---
  const BrandLogo = () => (
    <div className="flex items-center gap-3 select-none">
        <Logo className="w-8 h-8 text-white" />
        <div className="flex flex-col justify-center h-full">
            <h1 className="text-2xl font-bold tracking-tight text-white leading-none font-sans">
                Next<span className="text-cyan-400">waves</span>
            </h1>
        </div>
    </div>
  );

  return (
    <div className="fixed inset-0 flex bg-black text-zinc-100 font-sans">

      {/* --- DESKTOP DOCK (Left Rail - Glass) --- */}
      <nav className="hidden lg:flex flex-col w-24 bg-zinc-900/60 backdrop-blur-md border-r border-zinc-800 items-center py-8 z-30 shadow-2xl">
         <div className="mb-12">
            <div className="w-12 h-12 bg-zinc-800/80 rounded-2xl flex items-center justify-center border border-zinc-700/50 shadow-[0_0_20px_rgba(0,0,0,0.5)]">
                <Logo className="w-7 h-7 text-white" />
            </div>
         </div>

         <div className="flex flex-col gap-6 w-full px-4">
            <button 
                onClick={() => setActiveView('scanner')}
                className={`flex flex-col items-center gap-2 p-3 rounded-2xl transition-all duration-300 ${activeView === 'scanner' ? 'bg-white text-zinc-950 shadow-[0_0_15px_rgba(255,255,255,0.2)]' : 'text-zinc-500 hover:text-white hover:bg-zinc-800'}`}
            >
                <LayoutGrid size={22} strokeWidth={1.5} />
                <span className="text-[9px] font-bold tracking-widest uppercase">Dash</span>
            </button>

            <button 
                onClick={() => setActiveView('writer')}
                className={`flex flex-col items-center gap-2 p-3 rounded-2xl transition-all duration-300 ${activeView === 'writer' ? 'bg-white text-zinc-950 shadow-[0_0_15px_rgba(255,255,255,0.2)]' : 'text-zinc-500 hover:text-white hover:bg-zinc-800'}`}
            >
                <Cpu size={22} strokeWidth={1.5} />
                <span className="text-[9px] font-bold tracking-widest uppercase">Write</span>
            </button>
         </div>

         <div className="mt-auto mb-4">
             <div className={`w-2 h-2 rounded-full ${isConnected ? 'bg-emerald-500 shadow-[0_0_10px_#10b981]' : 'bg-red-500 shadow-[0_0_10px_#ef4444]'}`} title={status}></div>
         </div>
      </nav>

      {/* --- MAIN STAGE --- */}
      <div className="flex-1 flex flex-col relative overflow-hidden bg-gradient-to-br from-zinc-950 via-zinc-950 to-[#050505]">

        {/* Mobile Header */}
        <div className="lg:hidden h-16 bg-zinc-900/80 backdrop-blur flex items-center justify-between px-4 border-b border-zinc-800 z-20">
            <BrandLogo />
            <div className="flex items-center gap-3">
                 <div className={`w-1.5 h-1.5 rounded-full ${isConnected ? 'bg-emerald-500 shadow-[0_0_8px_#10b981]' : 'bg-red-500 shadow-[0_0_8px_#ef4444]'}`} />
                 <Button size="sm" variant={isConnected ? "danger" : "primary"} onClick={isConnected ? handleDisconnect : handleConnect}>
                    <Bluetooth size={16} />
                 </Button>
            </div>
        </div>

        {/* Content Wrapper */}
        <div className="flex-1 overflow-hidden relative p-0 lg:p-6 lg:gap-6 flex flex-col">

            {activeView === 'scanner' && (
                <div className="w-full h-full flex flex-col lg:flex-row gap-6">
                    {/* LEFT: Controls (Vehicle Status) */}
                    <div className={`
                        ${mobileTab === 'controls' ? 'flex' : 'hidden'} 
                        lg:flex flex-col w-full lg:w-[360px] shrink-0 bg-zinc-900/40 backdrop-blur-md lg:rounded-3xl border border-zinc-800/60 overflow-hidden shadow-2xl
                    `}>
                        <Controls 
                            status={status}
                            scanMode={scanMode}
                            isScanning={isScanning}
                            settings={settings}
                            onConnect={handleConnect}
                            onDisconnect={handleDisconnect}
                            onToggleMode={setScanMode}
                            onStartScan={handleStartScan}
                            onStopScan={handleStopScan}
                            onUpdateSettings={handleUpdateSettings}
                            onWriteEpc={handleWriteEpc}
                            writeLoading={writeStatus === 'pending'}
                            selectedEpc={selectedEpc}
                        />
                    </div>

                    {/* CENTER: Data Visualization (Flight Recorder) */}
                    <div className={`
                        ${mobileTab === 'logs' ? 'flex' : 'hidden'} 
                        lg:flex flex-col flex-1 bg-zinc-900/40 backdrop-blur-md lg:rounded-3xl border border-zinc-800/60 overflow-hidden min-w-0 shadow-2xl
                    `}>
                        <InteractiveLog 
                            tags={tags}
                            onClear={handleClearLog}
                            onSelectEpc={setSelectedEpc}
                            logs={logs}
                        />
                    </div>

                    {/* RIGHT: Batch (Console) */}
                    <div className={`
                        ${mobileTab === 'results' ? 'flex' : 'hidden'} 
                        lg:flex flex-col w-full lg:w-[320px] shrink-0 bg-zinc-900/40 backdrop-blur-md lg:rounded-3xl border border-zinc-800/60 overflow-hidden shadow-2xl
                    `}>
                        <BatchResults 
                            fileContent={fileContent}
                            isTransferring={isTransferring}
                            transferProgress={transferProgress} 
                            onRequestFile={handleRequestBatchFile}
                        />
                    </div>
                </div>
            )}

            {activeView === 'writer' && (
                <div className="w-full h-full bg-zinc-900/40 backdrop-blur-md lg:rounded-3xl border border-zinc-800/60 overflow-hidden shadow-2xl">
                    <WriterView 
                        onWrite={handleWriteEpc}
                        writeStatus={writeStatus}
                        writeMessage={writeMessage}
                        setWriteStatus={setWriteStatus}
                        onStartScan={handleStartScan}
                        onStopScan={handleStopScan}
                        isScanning={isScanning}
                        liveTags={tags}
                    />
                </div>
            )}

        </div>

        {/* Mobile Tab Bar */}
        {activeView === 'scanner' && (
            <div className="lg:hidden h-20 bg-zinc-950 border-t border-zinc-800 flex justify-around items-center z-20 pb-4">
                <button onClick={() => setMobileTab('controls')} className={mobileTab === 'controls' ? 'text-white' : 'text-zinc-600'}>
                    <LayoutGrid size={24} />
                </button>
                <button onClick={() => setMobileTab('logs')} className={mobileTab === 'logs' ? 'text-white' : 'text-zinc-600'}>
                    <ScrollText size={24} />
                </button>
                <button onClick={() => setMobileTab('results')} className={mobileTab === 'results' ? 'text-white' : 'text-zinc-600'}>
                    <Database size={24} />
                </button>
            </div>
        )}

      </div>
    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { Bluetooth, Radio, Play, Square, Wifi, Volume2, Zap, ChevronDown, ChevronUp, Database, Activity, Power } from 'lucide-react';
import { Button } from './ui/Button';
import { Logo } from './ui/Logo';
import { ControlsProps, ScanMode, ConnectionStatus } from '../types';

export const Controls: React.FC<ControlsProps> = ({
  status,
  scanMode,
  isScanning,
  settings,
  onConnect,
  onDisconnect,
  onToggleMode,
  onStartScan,
  onStopScan,
  onUpdateSettings
}) => {

  const [localPower, setLocalPower] = useState(settings.power);
  const [localFreq, setLocalFreq] = useState(settings.frequency);
  const [localBuzzer, setLocalBuzzer] = useState(settings.buzzer);

  const [rfSpeed, setRfSpeed] = useState(1);
  const [rfQv, setRfQv] = useState(4);
  const [rfSession, setRfSession] = useState(1);
  const [rfTarget, setRfTarget] = useState(0);

  const [showRfSettings, setShowRfSettings] = useState(false);

  useEffect(() => { setLocalPower(settings.power); }, [settings.power]);
  useEffect(() => { setLocalFreq(settings.frequency); }, [settings.frequency]);
  useEffect(() => { setLocalBuzzer(settings.buzzer); }, [settings.buzzer]);
  useEffect(() => {
    if (settings.rfParams) {
      const parts = settings.rfParams.split(',').map(Number);
      if (parts.length === 4) { setRfSpeed(parts[0]); setRfQv(parts[1]); setRfSession(parts[2]); setRfTarget(parts[3]); }
    }
  }, [settings.rfParams]);

  const isConnected = status === ConnectionStatus.CONNECTED;
  const isPowerDirty = localPower !== settings.power;
  const isFreqDirty = localFreq !== settings.frequency;
  const isRfDirty = `${rfSpeed},${rfQv},${rfSession},${rfTarget}` !== settings.rfParams;

  return (
    <div className="flex flex-col h-full overflow-y-auto custom-scrollbar p-6 gap-8 bg-transparent text-zinc-100">

      {/* 1. Header with Brand */}
      <div className="hidden lg:flex items-center justify-between mb-2 opacity-80">
         <div className="flex items-center gap-3 select-none">
            <Logo className="w-6 h-6 text-white" />
            <div className="font-sans">
                <div className="text-sm font-bold text-white leading-none tracking-widest uppercase">Next<span className="text-cyan-400">waves</span></div>
                <div className="text-[9px] text-zinc-500 uppercase tracking-widest font-semibold mt-0.5">Control Unit</div>
            </div>
         </div>
      </div>

      {/* 2. Device Card (The "Tesla" Product View - Dark Matte) */}
      <div className="relative w-full bg-zinc-900 rounded-[2rem] p-6 flex flex-col gap-6 group transition-all border border-zinc-800 shadow-xl overflow-hidden">
          {/* Background Gradient Effect */}
          <div className={`absolute top-0 right-0 w-64 h-64 bg-cyan-500/10 blur-[80px] rounded-full pointer-events-none transition-opacity duration-1000 ${isConnected ? 'opacity-100' : 'opacity-0'}`}></div>

          {/* Status Badge */}
          <div className="flex justify-between items-start relative z-10">
              <div>
                  <h2 className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest mb-1">System State</h2>
                  <div className="flex items-center gap-2">
                      <div className={`w-1.5 h-1.5 rounded-full ${isConnected ? 'bg-cyan-400 shadow-[0_0_8px_#22d3ee]' : 'bg-zinc-700'}`}></div>
                      <span className={`text-xl font-bold tracking-tighter ${isConnected ? 'text-white' : 'text-zinc-500'}`}>
                          {status === ConnectionStatus.CONNECTED ? 'ONLINE' : status === ConnectionStatus.CONNECTING ? 'SYNCING...' : 'OFFLINE'}
                      </span>
                  </div>
              </div>
              <div className={`p-2 rounded-full border ${isConnected ? 'bg-cyan-950/30 border-cyan-500/30 text-cyan-400' : 'bg-zinc-800 border-zinc-700 text-zinc-500'}`}>
                  <Bluetooth size={18} />
              </div>
          </div>

          {/* Device Info Grid */}
          {isConnected ? (
              <div className="grid grid-cols-2 gap-3 relative z-10">
                  <div className="bg-zinc-950/50 p-4 rounded-2xl border border-zinc-800 flex flex-col justify-center">
                      <span className="text-[9px] text-zinc-500 uppercase font-bold block mb-1">Battery</span>
                      <span className="text-sm font-mono text-emerald-400 font-bold shadow-emerald-500/20 drop-shadow-sm">100%</span>
                  </div>
                  <div className="bg-zinc-950/50 p-4 rounded-2xl border border-zinc-800 flex flex-col justify-center min-w-0">
                      <span className="text-[9px] text-zinc-500 uppercase font-bold block mb-1">Unit ID</span>
                      <span className="text-[10px] font-mono text-zinc-300 font-bold break-all leading-tight">
                          {settings.deviceInfo || 'V3-Unknown'}
                      </span>
                  </div>
              </div>
          ) : (
             <div className="py-2 relative z-10">
                <Button fullWidth variant="primary" onClick={onConnect} disabled={status === ConnectionStatus.CONNECTING} className="shadow-[0_0_20px_rgba(255,255,255,0.1)]">
                    {status === ConnectionStatus.CONNECTING ? 'Initialising...' : 'Connect Scanner'}
                </Button>
             </div>
          )}

          {isConnected && (
             <button onClick={onDisconnect} disabled={isScanning} className="relative z-10 text-[9px] text-zinc-600 hover:text-red-400 font-bold uppercase tracking-widest text-center transition-colors">
                Terminate Connection
             </button>
          )}
      </div>

      {/* 3. Operation Modes (Pill Selectors) */}
      <div className="space-y-4">
          <label className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest ml-1">Operation Mode</label>
          <div className="bg-zinc-900 p-1.5 rounded-full flex relative border border-zinc-800">
              <button 
                  onClick={() => onToggleMode(ScanMode.INTERACTIVE)}
                  disabled={isScanning}
                  className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-full text-[10px] font-bold tracking-wider transition-all duration-300 ${scanMode === ScanMode.INTERACTIVE ? 'bg-zinc-800 text-white shadow-lg shadow-black/40 border border-zinc-700' : 'text-zinc-500 hover:text-zinc-300'}`}
              >
                  <Radio size={12} />
                  <span>LIVE</span>
              </button>
              <button 
                  onClick={() => onToggleMode(ScanMode.BATCH)}
                  disabled={isScanning}
                  className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-full text-[10px] font-bold tracking-wider transition-all duration-300 ${scanMode === ScanMode.BATCH ? 'bg-zinc-800 text-white shadow-lg shadow-black/40 border border-zinc-700' : 'text-zinc-500 hover:text-zinc-300'}`}
              >
                  <Database size={12} />
                  <span>BATCH</span>
              </button>
          </div>

          <Button 
             variant={isScanning ? 'danger' : 'success'} 
             fullWidth 
             size="lg"
             onClick={isScanning ? onStopScan : onStartScan}
             disabled={!isConnected}
             className="mt-4 shadow-xl"
          >
             {isScanning ? (
                <div className="flex items-center gap-3"><Square size={16} fill="currentColor" /> STOP SEQUENCE</div>
             ) : (
                <div className="flex items-center gap-3"><Play size={16} fill="currentColor" /> INITIATE SCAN</div>
             )}
          </Button>
      </div>

      {/* 4. Settings (Clean Sliders) */}
      <div className="space-y-6 pt-6 border-t border-zinc-800/50">

          {/* Power Slider */}
          <div>
              <div className="flex justify-between items-center mb-4 px-1">
                  <div className="flex items-center gap-2 text-zinc-400">
                      <Wifi size={14} />
                      <span className="text-[10px] font-bold uppercase tracking-widest">Signal Output</span>
                  </div>
