import React from 'react';
import { Download, FileDown, RefreshCw, Share2, FileCode } from 'lucide-react';
import { BatchResultsProps } from '../types';

export const BatchResults: React.FC<BatchResultsProps> = ({ 
  fileContent, 
  transferProgress, 
  isTransferring,
  onRequestFile
}) => {

  const handleDownload = () => {
    if (!fileContent) return;
    const blob = new Blob([fileContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `scan_batch_${new Date().toISOString()}.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleShare = async () => {
    if (!fileContent) return;
    try {
      const fileName = `scan_batch_${new Date().toISOString().slice(0, 19).replace(/:/g, '-')}.txt`;
      const file = new File([fileContent], fileName, { type: 'text/plain' });
      if (navigator.canShare && navigator.canShare({ files: [file] })) {
        await navigator.share({
          files: [file],
          title: 'Batch Scan Results',
          text: 'Attached RFID scan results.',
        });
      } else {
        if (navigator.share) {
             await navigator.share({
                title: 'Batch Scan Results',
                text: fileContent
             });
        } else {
             alert('Sharing is not supported on this device/browser. Please use "Save .txt"');
        }
      }
    } catch (error) {
      console.log('Share canceled or failed', error);
    }
  };

  const hasContent = !!fileContent && !isTransferring;
  const canShare = typeof navigator !== 'undefined' && !!navigator.share;

  return (
    <div className="w-full flex flex-col h-full p-6 gap-4 bg-transparent">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-3 pb-2 border-b border-zinc-800">
        <div className="flex items-center gap-2 text-white font-bold uppercase tracking-widest text-xs">
          <FileDown className="w-4 h-4 text-cyan-500" />
          <h2>Data Export</h2>
        </div>

        <div className="flex flex-wrap items-center gap-2">
            <button 
                onClick={onRequestFile}
                disabled={isTransferring}
                className="flex items-center gap-1.5 px-3 py-1.5 bg-zinc-800 hover:bg-zinc-700 text-zinc-300 hover:text-white rounded text-[10px] font-bold uppercase border border-zinc-700 transition-colors disabled:opacity-50"
            >
                <RefreshCw className={`w-3 h-3 ${isTransferring ? 'animate-spin' : ''}`} />
                FETCH DATA
            </button>

            {hasContent && (
              <>
                <button 
                    onClick={handleDownload}
                    className="flex items-center gap-1.5 px-3 py-1.5 bg-cyan-900/20 hover:bg-cyan-900/40 text-cyan-400 hover:text-cyan-300 rounded text-[10px] font-bold uppercase border border-cyan-800/50 transition-colors"
                >
                    <Download className="w-3 h-3" />
                    SAVE
                </button>

                {canShare && (
                    <button 
                        onClick={handleShare}
                        className="flex items-center gap-1.5 px-3 py-1.5 bg-zinc-800 hover:bg-zinc-700 text-zinc-400 hover:text-white rounded text-[10px] font-bold uppercase border border-zinc-700 transition-colors"
                    >
                        <Share2 className="w-3 h-3" />
                    </button>
                )}
              </>
            )}
        </div>
      </div>

      <div className="flex-1 bg-black/50 rounded-lg border border-zinc-800 overflow-hidden relative flex flex-col shadow-inner">
        {isTransferring ? (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-900/90 z-10 p-8 text-center backdrop-blur-sm">
            <RefreshCw className="w-8 h-8 text-cyan-500 animate-spin mb-4" />
            <h3 className="text-cyan-400 font-bold uppercase tracking-widest text-xs">TRANSFERRING PACKETS...</h3>
            {transferProgress >= 0 && (
                <div className="w-48 h-1 bg-zinc-800 rounded-full mt-4 overflow-hidden">
                    <div className="h-full bg-cyan-500 transition-all duration-300 box-shadow-[0_0_10px_#22d3ee]" style={{width: `${transferProgress}%`}}></div>
                </div>
            )}
            <p className="text-zinc-500 text-[9px] font-mono mt-4">MAINTAIN CONNECTION</p>
          </div>
        ) : !fileContent ? (
          <div className="flex-1 flex flex-col items-center justify-center text-zinc-700 p-8 text-center gap-3">
            <FileCode className="w-12 h-12 opacity-20" />
            <p className="text-xs font-bold text-zinc-600 uppercase tracking-widest">Buffer Empty</p>
            <p className="text-[10px] max-w-xs font-mono opacity-40">Use BATCH mode to accumulate data.</p>
          </div>
        ) : (
          <div className="flex-1 overflow-auto p-4 custom-scrollbar bg-black/80">
            <pre className="font-mono text-[10px] text-zinc-400 whitespace-pre-wrap break-all leading-relaxed">
              {fileContent}
            </pre>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ArrowRight, AlertTriangle, Radio, CheckCircle2, XCircle, Search, Binary, Database, Cpu } from 'lucide-react';
import { Button } from './ui/Button';
import { Input } from './ui/Input';
import { Tag, WriteStatus } from '../types';

interface WriterViewProps {
  onWrite: (oldEpc: string, newEpc: string) => void;
  writeStatus: WriteStatus;
  writeMessage: string;
  setWriteStatus: (status: WriteStatus) => void;
  onStartScan: () => void;
  onStopScan: () => void;
  isScanning: boolean;
  liveTags: Tag[];
}

export const WriterView: React.FC<WriterViewProps> = ({
  onWrite,
  writeStatus,
  writeMessage,
  setWriteStatus,
  onStartScan,
  onStopScan,
  isScanning,
  liveTags
}) => {
  const [step, setStep] = useState<1 | 2>(1);
  const [targetEpc, setTargetEpc] = useState('');
  const [newEpc, setNewEpc] = useState('');
  const [error, setError] = useState('');

  const handleSelectTag = (epc: string) => {
    if (isScanning) onStopScan();
    setTargetEpc(epc);
    setNewEpc(epc); 
    setStep(2);
    setError('');
  };

  const handleBackToScan = () => {
    setStep(1);
    setTargetEpc('');
    setWriteStatus('idle');
  };

  const validateAndWrite = () => {
    const hexRegex = /^[0-9A-Fa-f]+$/;
    if (!hexRegex.test(newEpc)) {
      setError('HEX CHARACTERS ONLY (0-9, A-F)');
      return;
    }
    if (newEpc.length === 0 || newEpc.length % 4 !== 0) {
        setError(`INVALID LENGTH (MUST BE MULTIPLE OF 4). CURRENT: ${newEpc.length}`);
        return;
    }
    setError('');
    onWrite(targetEpc, newEpc);
  };

  return (
    <div className="w-full h-full flex flex-col p-4 lg:p-10 overflow-y-auto bg-transparent">
        <div className="max-w-3xl mx-auto w-full flex flex-col gap-8">

            {/* Header */}
            <div className="flex items-center gap-6 pb-6 border-b border-zinc-800">
                <div className="p-4 bg-zinc-900 rounded-2xl border border-zinc-800 shadow-lg">
                    <Cpu className="w-8 h-8 text-cyan-400" strokeWidth={1.5} />
                </div>
                <div>
                    <h1 className="text-xl font-bold text-white tracking-widest font-sans uppercase">Memory Encoder</h1>
                    <p className="text-zinc-500 text-xs font-mono uppercase tracking-wide mt-1">Bank 1: EPC Gen2 Interface</p>
                </div>
            </div>

            {/* Warning Panel */}
            <div className="bg-amber-950/20 border border-amber-900/50 rounded-lg p-4 flex items-start gap-4">
                <AlertTriangle className="w-5 h-5 text-amber-500 shrink-0 mt-0.5 animate-pulse" />
                <div className="space-y-1">
                    <p className="text-[10px] font-bold text-amber-500 uppercase tracking-widest">Proximity Alert</p>
                    <p className="text-[10px] text-amber-200/60 leading-relaxed font-mono">
                        ISOLATION REQUIRED. Ensure only TARGET TAG is within antenna range during write cycles.
                    </p>
                </div>
            </div>

            {/* Step 1: Scan & Select */}
            {step === 1 && (
                <div className="flex flex-col gap-4 animate-in slide-in-from-right-4 duration-300 fade-in">
                    <div className="flex items-center justify-between bg-zinc-900/50 p-6 rounded-xl border border-zinc-800 shadow-sm backdrop-blur-sm">
                        <div className="flex items-center gap-4">
                             <div className="flex items-center justify-center w-8 h-8 rounded bg-zinc-800 text-white font-bold border border-zinc-700 text-sm">1</div>
                             <div>
                                 <h3 className="text-white font-bold text-xs uppercase tracking-wider">Select Target</h3>
                                 <p className="text-[10px] text-zinc-500 font-mono mt-1">Scan environment to identify target EPC.</p>
                             </div>
                        </div>
                        {isScanning ? (
                            <Button size="sm" variant="danger" onClick={onStopScan} className="min-w-[100px] shadow-red-900/20">STOP SCAN</Button>
                        ) : (
                            <Button size="sm" variant="success" onClick={onStartScan} className="min-w-[100px] shadow-cyan-900/20">START SCAN</Button>
                        )}
                    </div>

                    <div className="bg-black/40 border border-zinc-800 rounded-xl min-h-[300px] flex-1 overflow-hidden flex flex-col relative shadow-inner">
                        {/* Grid lines overlay */}
                        <div className="absolute inset-0 bg-[url('data:image/svg+xml;base64,PHN2ZyB3aWR0aD0iMjAiIGhlaWdodD0iMjAiIHhtbG5zPSJodHRwOi8vd3d3LnczLm9yZy8yMDAwL3N2ZyI+PGNpcmNsZSBjeD0iMSIgY3k9IjEiIHI9IjEiIGZpbGw9InJnYmEoMjU1LDI1NSwyNTUsMC4wNSkiLz48L3N2Zz4=')] pointer-events-none opacity-50"></div>

                        <div className="bg-zinc-900/80 px-4 py-2 border-b border-zinc-800 text-[9px] font-bold text-cyan-500 flex justify-between uppercase tracking-widest backdrop-blur">
                            <span>Detected Signals</span>
                            <span>{liveTags.length} UNITS</span>
                        </div>
                        <div className="flex-1 overflow-y-auto relative custom-scrollbar z-10">
                            {liveTags.length === 0 ? (
                                <div className="absolute inset-0 flex flex-col items-center justify-center text-zinc-600 gap-4">
                                    <div className="relative">
                                        <div className={`absolute inset-0 bg-cyan-500 blur-[40px] opacity-10 rounded-full ${isScanning ? 'animate-pulse' : 'hidden'}`}></div>
                                        <Radio className={`w-12 h-12 ${isScanning ? 'text-cyan-500' : 'text-zinc-700'}`} strokeWidth={1} />
                                    </div>
                                    <p className="text-[10px] font-mono uppercase tracking-widest">{isScanning ? 'SCANNING FREQUENCIES...' : 'SYSTEM IDLE'}</p>
                                </div>
                            ) : (
                                <div className="divide-y divide-zinc-800/50">
                                    {liveTags.map((tag, idx) => (
                                        <button 
                                            key={idx}
                                            onClick={() => handleSelectTag(tag.epc)}
