import React, { useState, useEffect, useRef, useCallback } from 'react';
import { LayoutGrid, ScrollText, Database, Bluetooth, Cpu, ScanLine, Zap, Settings as SettingsIcon } from 'lucide-react';
import { bleService } from './services/bleService';
import { Controls } from './components/Controls';
import { InteractiveLog } from './components/InteractiveLog';
import { BatchResults } from './components/BatchResults';
import { WriterView } from './components/WriterView';
import { Button } from './components/ui/Button';
import { Logo } from './components/ui/Logo';
import { 
  ConnectionStatus, 
  ScanMode, 
  Tag, 
  Settings, 
  LogEntry,
  WriteStatus
} from './types';

type AppView = 'scanner' | 'writer' | 'settings';

function App() {
  // --- State ---
  const [activeView, setActiveView] = useState<AppView>('scanner');

  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [scanMode, setScanMode] = useState<ScanMode>(ScanMode.INTERACTIVE);
  const [isScanning, setIsScanning] = useState(false);

  // Mobile Tabs
  const [mobileTab, setMobileTab] = useState<'controls' | 'logs' | 'results'>('controls');

  // Settings
  const [settings, setSettings] = useState<Settings>({
    power: 30,
    frequency: 'US',
    rfParams: '1,4,1,0',
    buzzer: true,
    deviceInfo: ''
  });

  // Data
  const [tags, setTags] = useState<Tag[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [selectedEpc, setSelectedEpc] = useState('');

  // File Transfer
  const [fileContent, setFileContent] = useState<string>('');
  const [isTransferring, setIsTransferring] = useState(false);
  const [transferProgress, setTransferProgress] = useState(-1);

  // Write EPC State
  const [writeStatus, setWriteStatus] = useState<WriteStatus>('idle');
  const [writeMessage, setWriteMessage] = useState('');

  // --- Refs ---
  const tagBufferRef = useRef<Map<string, Tag>>(new Map());
  const lastRenderTimeRef = useRef(0);
  const animationFrameRef = useRef<number>(0);

  // --- Helpers ---
  const addLog = useCallback((message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [...prev.slice(-100), { type, message, timestamp: Date.now() }]);
  }, []);

  // --- BLE Logic (Simplified for brevity - logic remains same) ---
  const handleDataReceived = useCallback((data: any) => {
    if (data.cmd === 'live_tag' && data.epc) {
        const existing = tagBufferRef.current.get(data.epc);
        if (existing) {
            existing.count += 1;
            existing.rssi = data.rssi;
            tagBufferRef.current.set(data.epc, existing);
        } else {
            const newTag: Tag = { epc: data.epc, timestamp: Date.now(), rssi: data.rssi, count: 1 };
            tagBufferRef.current.set(data.epc, newTag);
        }
        return;
    }
    if (data.cmd === 'DI') { setSettings(prev => ({ ...prev, deviceInfo: data.val })); addLog(`Device Info: ${data.val}`, 'rx'); }
    if (data.cmd === 'GP') setSettings(prev => ({ ...prev, power: data.val }));
    if (data.cmd === 'GF') setSettings(prev => ({ ...prev, frequency: data.val }));
    if (data.cmd === 'GRP') setSettings(prev => ({ ...prev, rfParams: data.val }));
    if (data.cmd === 'BZ') setSettings(prev => ({ ...prev, buzzer: data.val === 'on' }));
    if (data.cmd === 'WE') {
      if (data.status === 'ok') { setWriteStatus('success'); setWriteMessage(`Encoded: ${data.epc}`); addLog(`Encode Success: ${data.epc}`, 'info'); } 
      else { setWriteStatus('error'); setWriteMessage('Encoding failed. Check log.'); addLog('Encode Failed.', 'error'); }
    }
  }, [addLog]);

  const handleFileEvent = useCallback((event: 'start' | 'progress' | 'complete' | 'error', data?: any) => {
    if (event === 'start') { setIsTransferring(true); setTransferProgress(0); setFileContent(''); addLog(`File transfer started...`, 'info'); } 
    else if (event === 'progress') { setTransferProgress(data); } 
    else if (event === 'complete') { setIsTransferring(false); setTransferProgress(100); setFileContent(data); addLog('Transfer complete.', 'info'); } 
    else if (event === 'error') { setIsTransferring(false); setTransferProgress(-1); addLog(`Transfer error: ${data}`, 'error'); }
  }, [addLog]);

  useEffect(() => {
    bleService.setCallbacks(handleDataReceived, (msg, type) => addLog(msg, type), handleFileEvent);
  }, [handleDataReceived, addLog, handleFileEvent]);

  useEffect(() => {
    const renderLoop = () => {
      const now = Date.now();
      // Increased interval to 250ms to reduce render frequency with large datasets
      if (now - lastRenderTimeRef.current > 250 && tagBufferRef.current.size > 0) {
        const allTags: Tag[] = Array.from(tagBufferRef.current.values());
        allTags.sort((a, b) => a.timestamp - b.timestamp);
        // Removed .slice(0, 500) to display all tags
        setTags(allTags);
        lastRenderTimeRef.current = now;
      }
      animationFrameRef.current = requestAnimationFrame(renderLoop);
    };
    animationFrameRef.current = requestAnimationFrame(renderLoop);
    return () => { if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current); };
  }, []);

  const handleConnect = async () => {
    try { setStatus(ConnectionStatus.CONNECTING); await bleService.connect(); setStatus(ConnectionStatus.CONNECTED); setTimeout(async () => { try { await bleService.getSettings(); } catch(e) {} }, 500); } catch (e) { setStatus(ConnectionStatus.ERROR); }
  };
  const handleDisconnect = () => { bleService.disconnect(); setStatus(ConnectionStatus.DISCONNECTED); setIsScanning(false); };
  const handleStartScan = async () => { if (status !== ConnectionStatus.CONNECTED) return; try { await bleService.sendCommand({ cmd: scanMode === ScanMode.INTERACTIVE ? 'S' : 'SB' }); setIsScanning(true); } catch (e: any) { addLog(e.message, 'error'); } };
  const handleStopScan = async () => { if (status !== ConnectionStatus.CONNECTED) return; try { await bleService.sendCommand({ cmd: scanMode === ScanMode.INTERACTIVE ? 'X' : 'XB' }); if (scanMode === ScanMode.BATCH) setTimeout(() => bleService.requestFileTransfer(), 500); setIsScanning(false); } catch (e: any) { addLog(e.message, 'error'); } };
  const handleRequestBatchFile = async () => { if (!isTransferring) { setFileContent(''); await bleService.requestFileTransfer(); } };
  const handleUpdateSettings = async (key: keyof Settings, value: string | number | boolean) => {
    setSettings(prev => ({ ...prev, [key]: value }));
    if (status !== ConnectionStatus.CONNECTED) return;
    let cmd = {};
    if (key === 'power') cmd = { cmd: 'SP', val: value };
    if (key === 'frequency') cmd = { cmd: 'SF', val: value };
    if (key === 'rfParams') cmd = { cmd: 'SRP', val: value };
    if (key === 'buzzer') cmd = { cmd: 'BZ', val: value ? 'on' : 'off' };
    await bleService.sendCommand(cmd);
  };
  const handleWriteEpc = async (oldEpc: string, newEpc: string) => { setWriteStatus('pending'); setWriteMessage(''); try { await bleService.sendCommand({ cmd: 'WE', old: oldEpc, new: newEpc }); } catch (e: any) { setWriteStatus('error'); setWriteMessage(e.message); } };
  const handleClearLog = () => { tagBufferRef.current.clear(); setTags([]); };

  const isConnected = status === ConnectionStatus.CONNECTED;

  // --- Brand Logo Component ---
  const BrandLogo = () => (
    <div className="flex items-center gap-3 select-none">
        <Logo className="w-8 h-8" />
        <div className="flex flex-col justify-center h-full">
            <h1 className="text-2xl font-bold tracking-tight text-slate-900 leading-none font-sans">
                Next<span className="text-cyan-500">waves</span>
            </h1>
        </div>
    </div>
  );

  return (
    <div className="fixed inset-0 flex bg-ui-bg text-slate-800 font-sans">

      {/* --- DESKTOP DOCK (Left Rail) --- */}
      <nav className="hidden lg:flex flex-col w-24 bg-white border-r border-ui-border items-center py-8 z-30 shadow-sm">
         <div className="mb-12">
            <div className="w-12 h-12 bg-slate-50 rounded-xl flex items-center justify-center border border-slate-200 shadow-sm">
                <Logo className="w-8 h-8" />
            </div>
         </div>

         <div className="flex flex-col gap-6 w-full px-4">
            <button 
                onClick={() => setActiveView('scanner')}
                className={`flex flex-col items-center gap-2 p-3 rounded-xl transition-all duration-300 ${activeView === 'scanner' ? 'bg-slate-100 text-cyan-600 shadow-inner' : 'text-slate-400 hover:text-slate-600 hover:bg-slate-50'}`}
            >
                <LayoutGrid size={24} />
                <span className="text-[10px] font-semibold tracking-wide">Dashboard</span>
            </button>

            <button 
                onClick={() => setActiveView('writer')}
                className={`flex flex-col items-center gap-2 p-3 rounded-xl transition-all duration-300 ${activeView === 'writer' ? 'bg-slate-100 text-cyan-600 shadow-inner' : 'text-slate-400 hover:text-slate-600 hover:bg-slate-50'}`}
            >
                <Cpu size={24} />
                <span className="text-[10px] font-semibold tracking-wide">Encoder</span>
            </button>
         </div>

         <div className="mt-auto mb-4">
             <div className={`w-3 h-3 rounded-full ${isConnected ? 'bg-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.4)]' : 'bg-red-500 shadow-[0_0_10px_rgba(239,68,68,0.4)]'}`} title={status}></div>
         </div>
      </nav>

      {/* --- MAIN STAGE --- */}
      <div className="flex-1 flex flex-col relative overflow-hidden bg-ui-bg">

        {/* Mobile Header */}
        <div className="lg:hidden h-16 bg-white flex items-center justify-between px-4 border-b border-ui-border z-20 shadow-sm">
            <BrandLogo />
            <div className="flex items-center gap-3">
                 <div className={`w-2 h-2 rounded-full ${isConnected ? 'bg-emerald-500' : 'bg-red-500'}`} />
                 <Button size="sm" variant={isConnected ? "danger" : "primary"} onClick={isConnected ? handleDisconnect : handleConnect}>
                    <Bluetooth size={16} />
                 </Button>
            </div>
        </div>

        {/* Content Wrapper */}
        <div className="flex-1 overflow-hidden relative p-0 lg:p-6">

            {activeView === 'scanner' && (
                <div className="w-full h-full flex flex-col lg:flex-row gap-6">
                    {/* LEFT: Controls (The Dashboard) */}
                    <div className={`
                        ${mobileTab === 'controls' ? 'flex' : 'hidden'} 
                        lg:flex flex-col w-full lg:w-[360px] shrink-0 bg-white lg:rounded-2xl border border-ui-border overflow-hidden shadow-soft
                    `}>
                        <Controls 
                            status={status}
                            scanMode={scanMode}
                            isScanning={isScanning}
                            settings={settings}
                            onConnect={handleConnect}
                            onDisconnect={handleDisconnect}
                            onToggleMode={setScanMode}
                            onStartScan={handleStartScan}
                            onStopScan={handleStopScan}
                            onUpdateSettings={handleUpdateSettings}
                            onWriteEpc={handleWriteEpc}
                            writeLoading={writeStatus === 'pending'}
                            selectedEpc={selectedEpc}
                        />
                    </div>

                    {/* CENTER: Data Visualization */}
                    <div className={`
                        ${mobileTab === 'logs' ? 'flex' : 'hidden'} 
                        lg:flex flex-col flex-1 bg-white lg:rounded-2xl border border-ui-border overflow-hidden min-w-0 shadow-soft
                    `}>
                        <InteractiveLog 
                            tags={tags}
                            onClear={handleClearLog}
                            onSelectEpc={setSelectedEpc}
                            logs={logs}
                        />
                    </div>

                    {/* RIGHT: History/Batch (Collapsed on smaller desktops if needed) */}
                    <div className={`
                        ${mobileTab === 'results' ? 'flex' : 'hidden'} 
                        lg:flex flex-col w-full lg:w-[320px] shrink-0 bg-white lg:rounded-2xl border border-ui-border overflow-hidden shadow-soft
                    `}>
                        <BatchResults 
                            fileContent={fileContent}
                            isTransferring={isTransferring}
                            transferProgress={transferProgress} 
                            onRequestFile={handleRequestBatchFile}
                        />
                    </div>
                </div>
            )}

            {activeView === 'writer' && (
                <div className="w-full h-full bg-white lg:rounded-2xl border border-ui-border overflow-hidden shadow-soft">
                    <WriterView 
                        onWrite={handleWriteEpc}
                        writeStatus={writeStatus}
                        writeMessage={writeMessage}
                        setWriteStatus={setWriteStatus}
                        onStartScan={handleStartScan}
                        onStopScan={handleStopScan}
                        isScanning={isScanning}
                        liveTags={tags}
                    />
                </div>
            )}

        </div>

        {/* Mobile Tab Bar */}
        {activeView === 'scanner' && (
            <div className="lg:hidden h-16 bg-white border-t border-ui-border flex justify-around items-center z-20">
                <button onClick={() => setMobileTab('controls')} className={mobileTab === 'controls' ? 'text-cyan-600' : 'text-slate-400'}>
                    <LayoutGrid />
                </button>
                <button onClick={() => setMobileTab('logs')} className={mobileTab === 'logs' ? 'text-cyan-600' : 'text-slate-400'}>
                    <ScrollText />
                </button>
                <button onClick={() => setMobileTab('results')} className={mobileTab === 'results' ? 'text-cyan-600' : 'text-slate-400'}>
                    <Database />
                </button>
            </div>
        )}

      </div>
    </div>
  );
}

export default App;

import React, { useRef, useEffect } from 'react';
import { Tag, LogEntry } from '../types';
import { Trash2, Terminal, Activity, Wifi } from 'lucide-react';
import { FixedSizeList } from 'react-window';
import AutoSizer from 'react-virtualized-auto-sizer';

interface InteractiveLogProps {
  tags: Tag[];
  onClear: () => void;
  onSelectEpc: (epc: string) => void;
  logs: LogEntry[];
}

// Row component for react-window
const Row = ({ index, style, data }: { index: number, style: React.CSSProperties, data: { tags: Tag[], onSelectEpc: (epc: string) => void } }) => {
  const { tags, onSelectEpc } = data;
  const tag = tags[index];

  // Handle case where tag might not exist, though it shouldn't happen with correct itemCount
  if (!tag) return null;

  return (
    <div 
      style={style}
      onClick={() => onSelectEpc(tag.epc)}
      className="grid grid-cols-12 items-center px-6 hover:bg-slate-50 cursor-pointer group transition-colors border-b border-slate-50"
    >
        <div className="col-span-1 text-slate-300 font-mono text-xs">{index + 1}</div>
        <div className="col-span-7 md:col-span-8 font-mono text-sm text-slate-700 group-hover:text-cyan-700 transition-colors font-medium tracking-tight">
            {tag.epc}
        </div>
        <div className="col-span-2 text-right font-mono text-xs text-slate-500 font-medium">
            {tag.rssi}
        </div>
        <div className="col-span-2 md:col-span-1 text-right">
            <span className="inline-block min-w-[30px] text-center bg-slate-100 text-slate-600 py-1 rounded-full text-[10px] font-mono font-bold">{tag.count}</span>
        </div>
    </div>
  );
};

export const InteractiveLog: React.FC<InteractiveLogProps> = ({ tags, onClear, onSelectEpc, logs }) => {
  const logEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (logEndRef.current) {
      logEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [logs]);

  return (
    <div className="flex-1 flex flex-col h-full min-w-0 bg-white">

      {/* 1. Header Area */}
      <div className="h-16 flex items-center justify-between px-6 border-b border-slate-100 bg-white sticky top-0 z-10">
          <div className="flex items-center gap-3">
              <div className="w-8 h-8 rounded-full bg-slate-50 flex items-center justify-center">
                  <Activity size={16} className="text-slate-900" />
              </div>
              <div>
                  <h2 className="text-sm font-bold text-slate-900 tracking-tight">Live Feed</h2>
                  <p className="text-[10px] text-slate-400 font-medium">Real-time transponder data</p>
              </div>
          </div>

          <div className="flex items-center gap-4">
              <div className="hidden md:flex items-center gap-2 px-3 py-1 bg-slate-50 rounded-full">
                  <span className={`w-2 h-2 rounded-full ${tags.length > 0 ? 'bg-emerald-500 animate-pulse' : 'bg-slate-300'}`}></span>
                  <span className="text-[10px] font-bold text-slate-500 uppercase">{tags.length} Tags</span>
              </div>
              <button 
                onClick={onClear} 
                className="text-xs font-bold text-slate-400 hover:text-red-500 transition-colors uppercase tracking-wider"
              >
                  Clear
              </button>
          </div>
      </div>

      {/* 2. Grid Header - Ultra Minimal */}
      <div className="grid grid-cols-12 px-6 py-3 bg-white text-[10px] font-bold text-slate-400 uppercase tracking-widest border-b border-slate-100">
          <div className="col-span-1">#</div>
          <div className="col-span-7 md:col-span-8">EPC Identifier</div>
          <div className="col-span-2 text-right">RSSI</div>
          <div className="col-span-2 md:col-span-1 text-right">Count</div>
      </div>

      {/* 3. Grid Body - Virtualized */}
      <div className="flex-1 overflow-y-auto bg-white relative">
          {tags.length === 0 ? (
              <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-300 gap-4">
                  <div className="w-20 h-20 rounded-full bg-slate-50 flex items-center justify-center">
                    <Wifi size={32} strokeWidth={2} className="opacity-20 text-slate-900" />
                  </div>
                  <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Waiting for signal</p>
              </div>
          ) : (
            <AutoSizer>
              {({ height, width }) => (
                <FixedSizeList
                  height={height}
                  width={width}
                  itemSize={56} // Height of each row in pixels (py-4 is 1rem top/bottom = 32px + content)
                  itemCount={tags.length}
                  itemData={{ tags, onSelectEpc }}
                  className="custom-scrollbar"
                >
                  {Row}
                </FixedSizeList>
              )}
            </AutoSizer>
          )}
      </div>

      {/* 4. Mini Diagnostics Log (Collapsible feel) */}
      <div className="h-40 border-t border-slate-100 bg-slate-50/50 flex flex-col">
          <div className="px-6 py-2 flex items-center gap-2">
              <span className="w-1.5 h-1.5 rounded-full bg-slate-300"></span>
              <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">System Events</span>
          </div>
          <div className="flex-1 overflow-y-auto px-6 pb-4 font-mono text-[10px] space-y-1.5 custom-scrollbar">
              {logs.map((log, i) => (
                  <div key={i} className="flex gap-4">
                      <span className="text-slate-300 select-none w-14">
                          {new Date(log.timestamp).toLocaleTimeString([], {hour12: false, hour: '2-digit', minute:'2-digit', second:'2-digit'})}
                      </span>
                      <span className={
                          log.type === 'error' ? 'text-red-500' :
                          log.type === 'tx' ? 'text-slate-400' :
                          log.type === 'rx' ? 'text-emerald-600' :
                          'text-slate-500'
                      }>
                          {log.message}
                      </span>
                  </div>
              ))}
              <div ref={logEndRef} />
          </div>
      </div>
    </div>
  );
};

