                className={`flex flex-col items-center gap-2 p-3 rounded-xl transition-all duration-300 ${activeView === 'scanner' ? 'bg-slate-100 text-cyan-600 shadow-inner' : 'text-slate-400 hover:text-slate-600 hover:bg-slate-50'}`}
            >
                <LayoutGrid size={24} />
                <span className="text-[10px] font-semibold tracking-wide">Dashboard</span>
            </button>

            <button 
                onClick={() => setActiveView('writer')}
                className={`flex flex-col items-center gap-2 p-3 rounded-xl transition-all duration-300 ${activeView === 'writer' ? 'bg-slate-100 text-cyan-600 shadow-inner' : 'text-slate-400 hover:text-slate-600 hover:bg-slate-50'}`}
            >
                <Cpu size={24} />
                <span className="text-[10px] font-semibold tracking-wide">Encoder</span>
            </button>
         </div>

         <div className="mt-auto mb-4">
             <div className={`w-3 h-3 rounded-full ${isConnected ? 'bg-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.4)]' : 'bg-red-500 shadow-[0_0_10px_rgba(239,68,68,0.4)]'}`} title={status}></div>
         </div>
