const getRssiColor = (rssi: number) => {
  if (rssi > -50) return 'bg-emerald-500'; // Strong
  if (rssi > -70) return 'bg-amber-500';  // Medium
  return 'bg-red-500';                    // Weak
};

// Maps RSSI from a weak signal (-85 dBm) to a strong signal (-30 dBm) as a 0-100 percentage.
const calculateRssiStrength = (rssi: number | undefined): number => {
    if (rssi === undefined) return 0;
    const minRssi = -85;
    const maxRssi = -30;
    // Clamp the RSSI value within the expected range
    const clampedRssi = Math.max(minRssi, Math.min(maxRssi, rssi));
    // Calculate percentage
    const percentage = ((clampedRssi - minRssi) / (maxRssi - minRssi)) * 100;
    return Math.round(percentage);
};


// Row component for react-window
const Row = ({ index, style, data }: { index: number, style: React.CSSProperties, data: { tags: Tag[], onSelectEpc: (epc: string) => void } }) => {
