import React, { useState, useEffect, useRef, useCallback } from 'react';
import { bleService } from './services/bleService';
import { Dock } from './components/ui/Dock';
import { ReadView } from './components/views/ReadView';
import { SettingsView } from './components/views/SettingsView';
import { 
  ConnectionStatus, 
  Tag, 
  Settings, 
  LogEntry
} from './types';

type AppView = 'read' | 'write' | 'settings' | 'test';

function App() {
  const [activeView, setActiveView] = useState<AppView>('read');
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [isScanning, setIsScanning] = useState(false);

  const [settings, setSettings] = useState<Settings>({
    power: 30,
    frequency: 'US',
    rfParams: '1,4,1,0',
    buzzer: true,
    deviceInfo: ''
  });

  const [tags, setTags] = useState<Tag[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);

  const tagBufferRef = useRef<Map<string, Tag>>(new Map());
  const lastRenderTimeRef = useRef(0);
  const animationFrameRef = useRef<number>(0);

  const addLog = useCallback((message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [...prev.slice(-100), { type, message, timestamp: Date.now() }]);
  }, []);

  const handleDataReceived = useCallback((data: any) => {
    if (data.cmd === 'live_tags' && Array.isArray(data.tags)) {
      data.tags.forEach((tag: { e?: string; r?: number; a?: number, t?: string }) => {
        if (tag.e) { 
          const existing = tagBufferRef.current.get(tag.e);
          if (existing) {
            existing.count += 1;
            existing.rssi = tag.r;
            existing.ant = tag.a;
            if(tag.t) existing.tid = tag.t;
            tagBufferRef.current.set(tag.e, existing);
          } else {
            const newTag: Tag = { epc: tag.e, timestamp: Date.now(), rssi: tag.r, count: 1, ant: tag.a, tid: tag.t };
            tagBufferRef.current.set(tag.e, newTag);
          }
        }
      });
      return;
    }

    if (data.cmd === 'DI') { setSettings(prev => ({ ...prev, deviceInfo: data.val })); addLog(`Device Info: ${data.val}`, 'rx'); }
    if (data.cmd === 'GP') setSettings(prev => ({ ...prev, power: data.val }));
  }, [addLog]);

  useEffect(() => {
    bleService.setCallbacks(handleDataReceived, (msg, type) => addLog(msg, type), () => {});
  }, [handleDataReceived, addLog]);

  useEffect(() => {
    const renderLoop = () => {
      const now = Date.now();
      if (now - lastRenderTimeRef.current > 250) { // Update regardless of buffer size to clear old tags if needed
        const allTags: Tag[] = Array.from(tagBufferRef.current.values());
        allTags.sort((a, b) => b.timestamp - a.timestamp); // Sort by most recent first
        setTags(allTags);
        lastRenderTimeRef.current = now;
      }
      animationFrameRef.current = requestAnimationFrame(renderLoop);
    };
    animationFrameRef.current = requestAnimationFrame(renderLoop);
    return () => { if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current); };
  }, []);

  const handleConnect = async () => {
    try { 
      setStatus(ConnectionStatus.CONNECTING); 
      await bleService.connect(); 
      setStatus(ConnectionStatus.CONNECTED); 
      setTimeout(async () => { 
        try { 
          await bleService.getSettings(); 
        } catch(e) { console.error(e) } 
      }, 500);
    } catch (e) { 
      setStatus(ConnectionStatus.ERROR); 
    }
  };

  const handleDisconnect = () => { 
    bleService.disconnect(); 
    setStatus(ConnectionStatus.DISCONNECTED); 
    setIsScanning(false); 
  };

  const handleStartScan = async () => {
    if (status !== ConnectionStatus.CONNECTED) return;
    try {
      await bleService.sendCommand({ cmd: 'S' });
      setIsScanning(true);
    } catch (e: any) { addLog(e.message, 'error'); }
  };

  const handleStopScan = async () => {
    if (status !== ConnectionStatus.CONNECTED) return;
    try {
      await bleService.sendCommand({ cmd: 'X' });
      setIsScanning(false);
    } catch (e: any) { addLog(e.message, 'error'); }
  };

  const handleClear = () => {
    tagBufferRef.current.clear();
    setTags([]);
  };

  const handleUpdateSettings = async (key: keyof Settings, value: string | number | boolean) => {
    setSettings(prev => ({ ...prev, [key]: value }));
    if (status !== ConnectionStatus.CONNECTED) return;
    let cmd = {};
    if (key === 'power') cmd = { cmd: 'SP', val: value };
    await bleService.sendCommand(cmd);
  };

  const renderView = () => {
    switch(activeView) {
      case 'read':
        return <ReadView 
                  tags={tags} 
                  isScanning={isScanning}
                  onStartScan={handleStartScan}
                  onStopScan={handleStopScan}
                  onClear={handleClear}
                />;
      case 'settings':
        return <SettingsView 
                  settings={settings}
                  onUpdateSettings={handleUpdateSettings}
                />;
      // Add 'write' and 'test' cases here later
      default:
        return <ReadView 
                  tags={tags} 
                  isScanning={isScanning}
                  onStartScan={handleStartScan}
                  onStopScan={handleStopScan}
                  onClear={handleClear}
                />;
    }
  }

  return (
    <div className="fixed inset-0 flex bg-slate-100 text-slate-800 font-sans">
      <Dock 
        activeView={activeView} 
        setActiveView={setActiveView}
        status={status}
        onConnect={handleConnect}
        onDisconnect={handleDisconnect}
      />
      <main className="flex-1 flex flex-col relative overflow-hidden">
        {renderView()}
      </main>
    </div>
  );
}

export default App;

