const getRssiColor = (rssi: number) => {
  if (rssi > -50) return 'bg-emerald-400';
  if (rssi > -70) return 'bg-amber-400';
  return 'bg-red-400';
};

const calculateRssiStrength = (rssi: number | undefined): number => {
    if (rssi === undefined) return 0;
    const minRssi = -90;
    const maxRssi = -30;
    const clampedRssi = Math.max(minRssi, Math.min(maxRssi, rssi));
    const percentage = ((clampedRssi - minRssi) / (maxRssi - minRssi)) * 100;
    return Math.round(percentage);
};

const TagRow = ({ index, style, data }: { index: number, style: React.CSSProperties, data: { tags: Tag[] } }) => {
  const tag = data.tags[index];
  if (!tag) return null;

  const rssiStrength = calculateRssiStrength(tag.rssi);
  const rssiColor = getRssiColor(tag.rssi ?? -100);

  return (
    <div style={style} className="grid grid-cols-12 gap-4 items-center px-6 text-sm border-b border-slate-100 font-mono">
      <div className="col-span-1 text-slate-400">{index + 1}</div>
      <div className="col-span-5 text-slate-800 truncate">{tag.epc}</div>
      <div className="col-span-2 text-slate-600">{tag.tid || '---'}</div>
      <div className="col-span-1 text-center text-slate-600 font-semibold">{tag.count}</div>
      <div className="col-span-1 text-center text-slate-600">{tag.ant || '-'}</div>
      <div className="col-span-1 text-center text-slate-600">{tag.rssi ?? '-'}</div>
      <div className="col-span-1 flex items-center">
        <div className="w-full h-1 bg-slate-200 rounded-full">
          <div className={`h-1 rounded-full ${rssiColor}`} style={{ width: `${rssiStrength}%` }}></div>
        </div>
      </div>
    </div>
  );
};

