const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

function App() {
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [activeMode, setActiveMode] = useState<ActiveMode>('none');
  const [isSwitchingMode, setIsSwitchingMode] = useState(false);

  const [settings, setSettings] = useState<Settings>({ power: 30, frequency: 'US', rfParams: '1,4,1,0', buzzer: true, deviceInfo: '' });

  // Data & State
  const [tags, setTags] = useState<Map<string, Tag>>(new Map());
  const [logs, setLogs] = useState<LogEntry[]>([]);

  // Find Mode State
  const [targetEpc, setTargetEpc] = useState('');
  const [foundTagRssi, setFoundTagRssi] = useState<number | null>(null);
  const [lastRssiUpdate, setLastRssiUpdate] = useState<number>(0);

  // File Transfer State
  const [fileContent, setFileContent] = useState<string>('');
  const [isTransferring, setIsTransferring] = useState(false);
  const [transferProgress, setTransferProgress] = useState(-1);

  const tagRenderBuffer = useRef<Map<string, Tag>>(new Map());
  const animationFrameRef = useRef<number>(0);

  const addLog = useCallback((message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [...prev.slice(-100), { type, message, timestamp: Date.now() }]);
  }, []);

  const handleDataReceived = useCallback((data: any) => {
    if (data.cmd !== 'live_tags' || !Array.isArray(data.tags)) return;

    const newTags = new Map(tagRenderBuffer.current);
    let targetFoundInPacket = false;

    data.tags.forEach((tag: { e?: string; r?: number }) => {
      if (!tag.e) return;

      // Update interactive list buffer
      const existing = newTags.get(tag.e);
      if (existing) {
        existing.count += 1;
        existing.rssi = tag.r;
        existing.timestamp = Date.now();
      } else {
        newTags.set(tag.e, { epc: tag.e, timestamp: Date.now(), rssi: tag.r, count: 1 });
      }

      // Check for target EPC in Find mode
      if (activeMode === 'find' && tag.e === targetEpc) {
        setFoundTagRssi(tag.r ?? null);
        setLastRssiUpdate(Date.now());
        targetFoundInPacket = true;
      }
    });

    tagRenderBuffer.current = newTags;

    // If in find mode and target was not in this packet, it triggers the decay logic in GeigerCounter
    if(activeMode === 'find' && !targetFoundInPacket) {
        // Let the Geiger component handle decay based on lastRssiUpdate timestamp
    }

  }, [activeMode, targetEpc]);

  const handleFileEvent = useCallback((event: 'start' | 'progress' | 'complete' | 'error', data?: any) => {
    if (event === 'start') { setIsTransferring(true); setTransferProgress(0); setFileContent(''); addLog(`File transfer started...`, 'info'); } 
    else if (event === 'progress') { setTransferProgress(data); } 
    else if (event === 'complete') { setIsTransferring(false); setTransferProgress(100); setFileContent(data); addLog('Transfer complete.', 'info'); } 
    else if (event === 'error') { setIsTransferring(false); setTransferProgress(-1); addLog(`Transfer error: ${data}`, 'error'); }
  }, [addLog]);

  useEffect(() => {
    bleService.setCallbacks(handleDataReceived, (msg, type) => addLog(msg, type), handleFileEvent);
  }, [handleDataReceived, addLog, handleFileEvent]);

  useEffect(() => {
    const renderLoop = () => {
      if (tagRenderBuffer.current.size !== tags.size || activeMode === 'interactive') {
          setTags(new Map(tagRenderBuffer.current));
      }
      animationFrameRef.current = requestAnimationFrame(renderLoop);
    };
    animationFrameRef.current = requestAnimationFrame(renderLoop);
    return () => cancelAnimationFrame(animationFrameRef.current);
  }, [tags.size, activeMode]);

  const handleConnect = async () => {
    try { setStatus(ConnectionStatus.CONNECTING); await bleService.connect(); setStatus(ConnectionStatus.CONNECTED); setTimeout(async () => { try { await bleService.getSettings(); } catch(e) {} }, 500); } catch (e) { setStatus(ConnectionStatus.ERROR); }
  };
  const handleDisconnect = () => { bleService.disconnect(); setStatus(ConnectionStatus.DISCONNECTED); setActiveMode('none'); };

  const handleStop = async () => {
    const currentMode = activeMode;
    if (currentMode === 'none') return;

    setActiveMode('none');
    setFoundTagRssi(null);

    if (currentMode === 'interactive' || currentMode === 'find') {
      await bleService.sendCommand({ cmd: 'X' });
    } else if (currentMode === 'batch') {
      await bleService.sendCommand({ cmd: 'XB' });
      setTimeout(() => bleService.requestFileTransfer(), 500);
    }
  };

  const switchModeAndStart = async (newMode: ActiveMode, command: object) => {
    if (isSwitchingMode || !isConnected) return;

    setIsSwitchingMode(true);
    if (activeMode !== 'none') {
      await handleStop();
      await sleep(500);
    }

    if (newMode === 'interactive') tagRenderBuffer.current.clear();
    if (newMode === 'find') setFoundTagRssi(null);

    setActiveMode(newMode);
    await bleService.sendCommand(command);
    setIsSwitchingMode(false);
  };

  const handleStartInteractive = () => switchModeAndStart('interactive', { cmd: 'S' });
  const handleStartBatch = () => switchModeAndStart('batch', { cmd: 'SB' });
  const handleStartFind = () => { if(targetEpc) switchModeAndStart('find', { cmd: 'F', val: targetEpc }); };

  const handleTagClick = (epc: string) => setTargetEpc(epc);

  const isConnected = status === ConnectionStatus.CONNECTED;
  const isScanning = activeMode !== 'none';
  const sortedTags = Array.from(tags.values()).sort((a, b) => (b.timestamp || 0) - (a.timestamp || 0));

  return (
    <div className="fixed inset-0 flex flex-col bg-ui-bg text-slate-800 font-sans">
      <header className="h-16 bg-white flex items-center justify-between px-6 border-b border-ui-border z-20 shadow-sm">
          <div className="flex items-center gap-3 select-none">
            <Logo className="w-8 h-8" />
            <h1 className="text-xl font-bold tracking-tight text-slate-900 leading-none font-sans">
                Scanner<span className="text-cyan-500">OS</span> <span className="text-xs font-mono text-slate-400">v8.0</span>
            </h1>
          </div>
          <div className="flex items-center gap-4">
            <div className={`text-xs font-bold uppercase tracking-wider flex items-center gap-2 ${isConnected ? 'text-emerald-600' : 'text-slate-400'}`}>
               <div className={`w-2 h-2 rounded-full ${isConnected ? 'bg-emerald-500 animate-pulse' : 'bg-slate-300'}`}></div>
               {status}
            </div>
            <Button size="sm" variant={isConnected ? "secondary" : "primary"} onClick={isConnected ? handleDisconnect : handleConnect} disabled={status === ConnectionStatus.CONNECTING}>
              {status === ConnectionStatus.CONNECTING ? <LoaderCircle size={16} className="animate-spin" /> : <Bluetooth size={16} />}
              <span className="ml-2">{isConnected ? 'Disconnect' : 'Connect'}</span>
            </Button>
          </div>
      </header>

      <main className="flex-1 overflow-y-auto p-4 md:p-6 grid grid-cols-1 lg:grid-cols-3 gap-4 md:gap-6">

        {/* INTERACTIVE SCAN */}
        <section className="lg:col-span-1 bg-white rounded-2xl border border-ui-border shadow-soft flex flex-col">
          <div className="p-4 border-b border-ui-border">
            <h2 className="font-bold text-slate-800 flex items-center gap-2"><Radio size={16} className="text-cyan-500"/>Interactive Scan</h2>
            <p className="text-xs text-slate-500 mt-1">Live stream of all detected tags.</p>
          </div>
          <div className="flex-1 overflow-y-auto custom-scrollbar min-h-[200px]">
            {sortedTags.length === 0 && <div className="p-4 text-center text-xs text-slate-400">Scan to see tags.</div>}
            {sortedTags.map(tag => (
              <div key={tag.epc} onClick={() => handleTagClick(tag.epc)} className="p-3 border-b border-slate-100 hover:bg-cyan-50 cursor-pointer">
                <p className="font-mono text-xs text-slate-700">{tag.epc}</p>
                <p className="text-[10px] text-slate-500">RSSI: {tag.rssi ?? '-'} dBm | Count: {tag.count}</p>
              </div>
            ))}
          </div>
          <div className="p-4 border-t border-ui-border">
            {activeMode === 'interactive' ? (
              <Button fullWidth variant="danger" onClick={handleStop}>Stop Live Scan</Button>
            ) : (
              <Button fullWidth variant="secondary" onClick={handleStartInteractive} disabled={!isConnected || isSwitchingMode}>Start Live Scan</Button>
            )}
          </div>
        </section>

        {/* FIND MY ITEM */}
        <section className="lg:col-span-1 bg-white rounded-2xl border border-ui-border shadow-soft flex flex-col">
           <div className="p-4 border-b border-ui-border">
            <h2 className="font-bold text-slate-800 flex items-center gap-2"><Search size={16} className="text-cyan-500"/>Find My Item</h2>
            <p className="text-xs text-slate-500 mt-1">Pinpoint a specific tag with a Geiger counter.</p>
          </div>
          <div className="flex-1 p-4 flex flex-col justify-center items-center gap-4">
            <input 
              type="text" 
              value={targetEpc}
              onChange={e => setTargetEpc(e.target.value.toUpperCase())}
              placeholder="Paste or select an EPC"
              className="w-full text-center bg-slate-50 border border-slate-200 rounded-md px-3 py-2 font-mono text-sm"
            />
            <GeigerCounter rssi={foundTagRssi} lastSeenTimestamp={lastRssiUpdate} />
          </div>
          <div className="p-4 border-t border-ui-border">
             {activeMode === 'find' ? (
              <Button fullWidth variant="danger" onClick={handleStop}>Stop Finding</Button>
            ) : (
              <Button fullWidth variant="primary" onClick={handleStartFind} disabled={!isConnected || isSwitchingMode || !targetEpc}>Find Item</Button>
            )}
          </div>
        </section>

        {/* BATCH MODE */}
        <section className="lg:col-span-1 bg-white rounded-2xl border border-ui-border shadow-soft flex flex-col">
           <div className="p-4 border-b border-ui-border">
            <h2 className="font-bold text-slate-800 flex items-center gap-2"><Database size={16} className="text-cyan-500"/>Batch Mode</h2>
            <p className="text-xs text-slate-500 mt-1">Scan offline and download the results.</p>
          </div>
          <div className="flex-1">
            <BatchResults 
              fileContent={fileContent}
              isTransferring={isTransferring}
              transferProgress={transferProgress} 
              onRequestFile={() => bleService.requestFileTransfer()}
            />
          </div>
          <div className="p-4 border-t border-ui-border">
             {activeMode === 'batch' ? (
              <Button fullWidth variant="danger" onClick={handleStop}>Stop & Save</Button>
            ) : (
              <Button fullWidth variant="secondary" onClick={handleStartBatch} disabled={!isConnected || isSwitchingMode}>Start Batch Scan</Button>
            )}
          </div>
        </section>

      </main>
    </div>
  );
}

