import React, { useState, useEffect, useRef } from 'react';
import { Wifi } from 'lucide-react';

interface GeigerCounterProps {
  rssi: number | null;
  lastSeenTimestamp: number;
}

// Maps RSSI from a weak signal (-90 dBm) to a strong signal (-30 dBm) as a 0-100 percentage.
const calculateStrength = (rssi: number): number => {
    const minRssi = -90;
    const maxRssi = -30;
    const clampedRssi = Math.max(minRssi, Math.min(maxRssi, rssi));
    return Math.round(((clampedRssi - minRssi) / (maxRssi - minRssi)) * 100);
};

const getBarColor = (strength: number) => {
  if (strength > 75) return 'bg-emerald-500'; // Strong
  if (strength > 40) return 'bg-amber-500';  // Medium
  return 'bg-red-500';                    // Weak
};

export const GeigerCounter: React.FC<GeigerCounterProps> = ({ rssi, lastSeenTimestamp }) => {
  const [displayStrength, setDisplayStrength] = useState(0);
  const decayTimerRef = useRef<number | null>(null);

  useEffect(() => {
    // Clear any existing decay timer when a new signal arrives
    if (decayTimerRef.current) {
      clearInterval(decayTimerRef.current);
      decayTimerRef.current = null;
    }

    if (rssi !== null) {
      setDisplayStrength(calculateStrength(rssi));
    }

    // Set up a new decay timer
    const checkDecay = () => {
      if (Date.now() - lastSeenTimestamp > 500) { // Start decaying if no signal for 500ms
        if (!decayTimerRef.current) {
          decayTimerRef.current = window.setInterval(() => {
            setDisplayStrength(prev => {
              if (prev <= 0) {
                if(decayTimerRef.current) clearInterval(decayTimerRef.current);
                decayTimerRef.current = null;
                return 0;
              }
              return prev - 2; // Decay speed
            });
          }, 50); // Decay interval
        }
      }
    };

    const initialCheck = setTimeout(checkDecay, 500);

    return () => {
      clearTimeout(initialCheck);
      if (decayTimerRef.current) {
        clearInterval(decayTimerRef.current);
      }
    };
  }, [rssi, lastSeenTimestamp]);

  const barColor = getBarColor(displayStrength);

  return (
    <div className="w-full flex flex-col items-center justify-center gap-4 p-4 rounded-lg bg-slate-50 border border-slate-200 shadow-inner">
      <div className="w-full">
        <div className="flex justify-between items-baseline mb-1">
            <span className="text-xs font-bold text-slate-500 uppercase tracking-wider">Signal Strength</span>
            <span className="font-mono font-bold text-lg text-slate-800">{rssi !== null && displayStrength > 0 ? `${rssi} dBm` : '---'}</span>
        </div>
        <div className="w-full h-10 bg-slate-200 rounded-md overflow-hidden">
          <div 
            className={`h-full ${barColor} transition-all duration-100 ease-linear`} 
            style={{ width: `${displayStrength}%` }}
          ></div>
        </div>
      </div>
      <div className={`transition-opacity duration-300 ${displayStrength > 0 ? 'opacity-100' : 'opacity-30'}`}>
        <Wifi size={24} className="text-slate-400" />
      </div>
    </div>
  );
};

