interface BluetoothRemoteGATTCharacteristic extends EventTarget {
  value?: DataView;
  writeValue(value: BufferSource): Promise<void>;
  startNotifications(): Promise<BluetoothRemoteGATTCharacteristic>;
}
// --------------------------------------

const SERVICE_UUID = 0x00ff;
const CHAR_CMD_UUID = 0xff01;

// Callbacks
type DataCallback = (data: any) => void;
type LogCallback = (msg: string, type: 'info' | 'error' | 'rx' | 'tx') => void;

class BLEService {
  private device: BluetoothDevice | null = null;
  private server: BluetoothRemoteGATTServer | null = null;
  private charCmd: BluetoothRemoteGATTCharacteristic | null = null;

  private onDataReceived: DataCallback | null = null;
  private onLog: LogCallback | null = null;

  private commandQueue: Promise<void> = Promise.resolve();

  setCallbacks(onData: DataCallback, onLog: LogCallback) {
    this.onDataReceived = onData;
    this.onLog = onLog;
  }

  async connect(): Promise<void> {
    const nav = navigator as any;
    if (!nav.bluetooth) {
      throw new Error('Web Bluetooth is not supported in this browser.');
    }

    this.log('Requesting device...', 'info');

    try {
      this.device = await nav.bluetooth.requestDevice({
        filters: [{ namePrefix: 'Nextwaves_Scanner_V3' }],
        optionalServices: [SERVICE_UUID],
      });

      this.device!.addEventListener('gattserverdisconnected', this.handleDisconnect.bind(this));
      this.log(`Connecting to ${this.device!.name}...`, 'info');
      this.server = await this.device!.gatt!.connect();
      this.log('Getting Service...', 'info');
      const service = await this.server.getPrimaryService(SERVICE_UUID);
      this.log('Getting Characteristic...', 'info');
      this.charCmd = await service.getCharacteristic(CHAR_CMD_UUID);
      this.log('Starting Notifications...', 'info');
      await this.charCmd.startNotifications();
      this.charCmd.addEventListener('characteristicvaluechanged', this.handleCmdNotification.bind(this));
      this.log('Connected and ready.', 'info');
    } catch (error: any) {
      this.log(`Connection failed: ${error.message}`, 'error');
      this.disconnect();
      throw error;
    }
  }

  disconnect() {
    if (this.device && this.device.gatt?.connected) {
      this.device.gatt.disconnect();
    } else {
        this.handleDisconnect();
    }
  }

  private handleDisconnect() {
    this.log('Device disconnected.', 'error');
    this.device = null;
    this.server = null;
    this.charCmd = null;
  }

  private handleCmdNotification(event: Event) {
    const target = event.target as BluetoothRemoteGATTCharacteristic;
    if (!target.value) return;

    const decoder = new TextDecoder('utf-8');
    const value = decoder.decode(target.value);

    try {
        const data = JSON.parse(value);
        if (this.onDataReceived) {
            this.onDataReceived(data);
        }
        if (data.cmd !== 'live_tags') {
             this.log(`RX: ${value}`, 'rx');
        }
    } catch (e) {
        this.log(`RX (Non-JSON): ${value}`, 'rx');
    }
  }

  async sendCommand(command: object): Promise<void> {
    if (!this.charCmd) throw new Error('Not connected');

    const str = JSON.stringify(command);
    const encoder = new TextEncoder();
    const data = encoder.encode(str);

    this.commandQueue = this.commandQueue.then(async () => {
      try {
        this.log(`TX: ${str}`, 'tx');
        await this.charCmd?.writeValue(data);
      } catch (error: any) {
        this.log(`TX Failed: ${error.message}`, 'error');
        throw error;
      }
    });
    return this.commandQueue;
  }

  async getSettings(): Promise<void> {
    await this.sendCommand({ cmd: 'DI' });
    await this.sendCommand({ cmd: 'GP' });
    await this.sendCommand({ cmd: 'GF' });
    await this.sendCommand({ cmd: 'GRP' });
  }

  private log(msg: string, type: 'info' | 'error' | 'rx' | 'tx') {
    if (this.onLog) this.onLog(msg, type);
  }
}

export const bleService = new BLEService();

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { bleService } from './services/bleService';
import { ConnectionStatus, ActiveView, Tag, Settings, WriteStatus } from './types';
import { Wifi, Search, Pencil, Settings as SettingsIcon, Rss, BarChart, Hash, Cpu, LoaderCircle, CheckCircle, XCircle, Copy } from 'lucide-react';
import { Logo } from './components/ui/Logo';
import AutoSizer from 'react-virtualized-auto-sizer';
import { FixedSizeList } from 'react-window';

// --- UI COMPONENTS (Defined in-file for simplicity) ---

const Card: React.FC<{ children: React.ReactNode; className?: string }> = ({ children, className }) => (
  <div className={`bg-tesla-card rounded-2xl border border-tesla-border shadow-sm p-6 ${className}`}>{children}</div>
);

const Button: React.FC<React.ButtonHTMLAttributes<HTMLButtonElement> & { variant?: 'primary' | 'secondary' | 'danger' }> = ({ children, className, variant = 'primary', ...props }) => {
  const variants = {
    primary: 'bg-tesla-blue text-white hover:bg-opacity-90',
    secondary: 'bg-gray-200 text-tesla-heading hover:bg-gray-300',
    danger: 'bg-tesla-red text-white hover:bg-opacity-90',
  };
  return <button className={`px-4 py-2 rounded-lg font-semibold text-sm transition-all ${variants[variant]} disabled:opacity-50 ${className}`} {...props}>{children}</button>;
};

const Toggle: React.FC<{ checked: boolean; onChange: (checked: boolean) => void }> = ({ checked, onChange }) => (
  <button onClick={() => onChange(!checked)} className={`relative w-12 h-6 rounded-full transition-colors ${checked ? 'bg-tesla-blue' : 'bg-gray-300'}`}>
    <span className={`absolute left-1 top-1 w-4 h-4 bg-white rounded-full transition-transform ${checked ? 'transform translate-x-6' : ''}`} />
  </button>
);

// --- MAIN APP ---

function App() {
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [activeView, setActiveView] = useState<ActiveView>('monitor');
  const [isScanning, setIsScanning] = useState(false);
  const [settings, setSettings] = useState<Settings>({ power: 33, frequency: 'US', rfParams: '1,4,1,0', buzzer: true, deviceInfo: 'N/A' });
  const [tags, setTags] = useState<Map<string, Tag>>(new Map());
  const [readRate, setReadRate] = useState(0);

  // Encoder State
  const [encoderScanTags, setEncoderScanTags] = useState<Tag[]>([]);
  const [isEncoderScanning, setIsEncoderScanning] = useState(false);
  const [writeStatus, setWriteStatus] = useState<WriteStatus>('idle');
  const [writeMessage, setWriteMessage] = useState('');

  // Find State
  const [targetEpc, setTargetEpc] = useState('');
  const [foundTagRssi, setFoundTagRssi] = useState<number | null>(null);
  const [lastRssiUpdate, setLastRssiUpdate] = useState(0);

  const tagsReadInSecond = useRef(0);

  const handleDataReceived = useCallback((data: any) => {
    // Tag Data
    if (data.cmd === 'live_tags' && Array.isArray(data.tags)) {
      setTags(prevTags => {
        const newTags = new Map(prevTags);
        let targetFound = false;
        data.tags.forEach((tag: { e?: string; r?: number }) => {
          if (!tag.e) return;
          tagsReadInSecond.current++;
          const existing = newTags.get(tag.e);
          if (existing) {
            existing.count += 1;
            existing.rssi = tag.r;
            existing.timestamp = Date.now();
          } else {
            newTags.set(tag.e, { epc: tag.e, timestamp: Date.now(), rssi: tag.r, count: 1 });
          }
          if (tag.e === targetEpc) {
            setFoundTagRssi(tag.r ?? null);
            setLastRssiUpdate(Date.now());
            targetFound = true;
          }
        });
        if (!targetFound && activeView === 'find') {
            // Let Geiger decay logic handle it
        }
        return newTags;
      });
    }
    // Settings Responses
    if (data.cmd === 'DI') setSettings(s => ({ ...s, deviceInfo: data.val }));
    if (data.cmd === 'GP') setSettings(s => ({ ...s, power: data.val }));
    if (data.cmd === 'GF') setSettings(s => ({ ...s, frequency: data.val }));
    if (data.cmd === 'GRP') setSettings(s => ({ ...s, rfParams: data.val }));
    // Write Response
    if (data.cmd === 'WE') {
      if (data.status === 'ok') {
        setWriteStatus('success');
        setWriteMessage(`Success! New EPC: ${data.epc}`);
      } else {
        setWriteStatus('error');
        setWriteMessage(data.error || 'Write failed. Tag may be out of range.');
      }
    }
  }, [activeView, targetEpc]);

  useEffect(() => {
    bleService.setCallbacks(handleDataReceived, (msg, type) => console.log(`[${type}] ${msg}`));
    const rateInterval = setInterval(() => {
      setReadRate(tagsReadInSecond.current);
      tagsReadInSecond.current = 0;
    }, 1000);
    return () => clearInterval(rateInterval);
  }, [handleDataReceived]);

  const handleConnect = async () => {
    try {
      setStatus(ConnectionStatus.CONNECTING);
      await bleService.connect();
      setStatus(ConnectionStatus.CONNECTED);
      setTimeout(() => bleService.getSettings(), 500);
    } catch (e) {
      setStatus(ConnectionStatus.ERROR);
    }
  };

  const handleDisconnect = () => {
    bleService.disconnect();
    setStatus(ConnectionStatus.DISCONNECTED);
    setIsScanning(false);
    setTags(new Map());
  };

  const handleStartScan = async (mode: 'live' | 'find' | 'encoder') => {
    if (status !== ConnectionStatus.CONNECTED || isScanning) return;
    setIsScanning(true);
    setTags(new Map());

    let cmd: object = { cmd: 'S' };
    if(mode === 'find' && targetEpc) {
        cmd = { cmd: 'F', val: targetEpc };
    }

    if (mode === 'encoder') {
      setIsEncoderScanning(true);
      setEncoderScanTags([]);
      const encoderListener = (data: any) => {
        if (data.cmd === 'live_tags') {
          setEncoderScanTags(prev => {
            const newTags = [...prev];
            data.tags.forEach((t: any) => {
              if(!newTags.find(et => et.epc === t.e)) {
                newTags.push({epc: t.e, rssi: t.r, count: 1, timestamp: Date.now()});
              }
            });
            return newTags;
          });
        }
      };
      bleService.setCallbacks(encoderListener, (msg, type) => console.log(msg));
      await bleService.sendCommand({ cmd: 'S' });
      setTimeout(async () => {
        await bleService.sendCommand({ cmd: 'X' });
        setIsEncoderScanning(false);
        bleService.setCallbacks(handleDataReceived, (msg, type) => console.log(msg));
      }, 3000); // 3-second scan
      return;
    }

    await bleService.sendCommand(cmd);
  };

  const handleStopScan = async () => {
    if (status !== ConnectionStatus.CONNECTED) return;
    await bleService.sendCommand({ cmd: 'X' });
    setIsScanning(false);
  };

  const handleUpdateSetting = async (key: keyof Settings, value: any) => {
    setSettings(s => ({...s, [key]: value}));
    let cmd = {};
    if (key === 'power') cmd = {cmd: 'SP', val: value};
    if (key === 'frequency') cmd = {cmd: 'SF', val: value};
    if (key === 'buzzer') cmd = {cmd: 'BZ', val: value ? 'on' : 'off'};
    if (key === 'rfParams') cmd = {cmd: 'SRP', val: value};
    await bleService.sendCommand(cmd);
  }

  const handleWrite = async (oldEpc: string, newEpc: string) => {
    if (!oldEpc || !newEpc || newEpc.length !== 24 || !/^[0-9A-F]*$/i.test(newEpc)) {
        setWriteStatus('error');
        setWriteMessage('Invalid EPC format. Must be 24 hex characters.');
        return;
    }
    setWriteStatus('pending');
    setWriteMessage('');
    await bleService.sendCommand({ cmd: 'WE', old: oldEpc, new: newEpc });
    setTimeout(() => { if(writeStatus === 'pending') setWriteStatus('idle'); }, 5000); // Timeout
  }

  const sortedTags = useMemo(() => Array.from(tags.values()).sort((a, b) => b.timestamp - a.timestamp), [tags]);
  const peakRssi = useMemo(() => sortedTags.length > 0 ? Math.max(...sortedTags.map(t => t.rssi ?? -100)) : '-', [sortedTags]);

  const renderView = () => {
    switch (activeView) {
      case 'monitor': return <LiveMonitorView tags={sortedTags} peakRssi={peakRssi} readRate={readRate} totalTags={tags.size} />;
      case 'find': return <FindItemView onStart={() => handleStartScan('find')} onStop={handleStopScan} isScanning={isScanning} targetEpc={targetEpc} setTargetEpc={setTargetEpc} rssi={foundTagRssi} lastSeen={lastRssiUpdate} />;
      case 'encoder': return <TagEncoderView onScan={() => handleStartScan('encoder')} isScanning={isEncoderScanning} tags={encoderScanTags} onWrite={handleWrite} writeStatus={writeStatus} writeMessage={writeMessage} />;
      case 'settings': return <SettingsView settings={settings} onUpdate={handleUpdateSetting} />;
      default: return null;
    }
  };

  return (
    <div className="fixed inset-0 flex bg-tesla-bg text-tesla-heading font-sans">
      <Sidebar activeView={activeView} setActiveView={setActiveView} />
      <main className="flex-1 flex flex-col">
        <Header status={status} onConnect={handleConnect} onDisconnect={handleDisconnect} isScanning={isScanning} onStartScan={() => handleStartScan('live')} onStopScan={handleStopScan} activeView={activeView} />
        <div className="flex-1 overflow-y-auto p-6">{renderView()}</div>
      </main>
    </div>
  );
}

// --- SUB-COMPONENTS FOR VIEWS ---

const Sidebar: React.FC<{ activeView: ActiveView; setActiveView: (v: ActiveView) => void }> = ({ activeView, setActiveView }) => {
  const NavItem = ({ icon: Icon, label, view }: { icon: any; label: string; view: ActiveView }) => (
    <button onClick={() => setActiveView(view)} className={`flex flex-col items-center justify-center gap-1 w-full aspect-square rounded-lg transition-colors ${activeView === view ? 'bg-black/5 text-tesla-blue' : 'text-tesla-text hover:bg-black/5'}`}>
      <Icon size={24} />
      <span className="text-xs font-semibold">{label}</span>
    </button>
  );
  return (
    <aside className="w-24 bg-tesla-card border-r border-tesla-border flex flex-col items-center p-3 gap-2">
      <Logo className="w-12 h-12 mb-4" />
      <NavItem icon={Rss} label="Monitor" view="monitor" />
      <NavItem icon={Search} label="Find" view="find" />
      <NavItem icon={Pencil} label="Encoder" view="encoder" />
      <NavItem icon={SettingsIcon} label="Settings" view="settings" />
    </aside>
  );
};

const Header: React.FC<{ status: ConnectionStatus; onConnect: () => void; onDisconnect: () => void; isScanning: boolean; onStartScan: () => void; onStopScan: () => void, activeView: ActiveView }> = 
({ status, onConnect, onDisconnect, isScanning, onStartScan, onStopScan, activeView }) => (
  <header className="h-20 bg-tesla-card border-b border-tesla-border flex items-center justify-between px-6 flex-shrink-0">
    <div>
      <h1 className="text-2xl font-bold text-tesla-heading capitalize">{activeView}</h1>
    </div>
    <div className="flex items-center gap-4">
      {activeView === 'monitor' && (
        isScanning ? <Button variant="danger" onClick={onStopScan}>Stop Stream</Button> : <Button variant="primary" onClick={onStartScan} disabled={status !== ConnectionStatus.CONNECTED}>Start Stream</Button>
      )}
      <Button variant="secondary" onClick={status === ConnectionStatus.CONNECTED ? onDisconnect : onConnect} disabled={status === ConnectionStatus.CONNECTING}>
        {status === ConnectionStatus.CONNECTING ? <LoaderCircle className="animate-spin"/> : status === ConnectionStatus.CONNECTED ? 'Disconnect' : 'Connect'}
      </Button>
    </div>
  </header>
);

const LiveMonitorView: React.FC<{ tags: Tag[], totalTags: number, readRate: number, peakRssi: number | string }> = ({ tags, totalTags, readRate, peakRssi }) => {
    const TagRow = ({ index, style, data }: { index: number; style: React.CSSProperties; data: Tag[] }) => {
        const tag = data[index];
        const rssiStrength = tag.rssi ? Math.max(0, Math.min(100, ((tag.rssi + 90) / 60) * 100)) : 0;
        return (
            <div style={style} className="grid grid-cols-12 gap-4 items-center px-4 font-mono text-sm border-b border-tesla-border">
                <div className="col-span-1 text-tesla-text">{index + 1}</div>
                <div className="col-span-6 truncate">{tag.epc}</div>
                <div className="col-span-3">
                    <div className="w-full bg-gray-200 rounded-full h-2"><div className="bg-tesla-blue h-2 rounded-full" style={{width: `${rssiStrength}%`}}></div></div>
                </div>
                <div className="col-span-1 text-center">{tag.rssi ?? '-'}</div>
                <div className="col-span-1 text-center">{new Date(tag.timestamp).toLocaleTimeString()}</div>
            </div>
        );
    };

    return <>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-6">
            <Card><h3 className="text-tesla-text text-sm font-semibold">Total Tags</h3><p className="text-3xl font-bold mt-2">{totalTags}</p></Card>
            <Card><h3 className="text-tesla-text text-sm font-semibold">Read Rate</h3><p className="text-3xl font-bold mt-2">{readRate} <span className="text-base">tags/s</span></p></Card>
            <Card><h3 className="text-tesla-text text-sm font-semibold">Peak RSSI</h3><p className="text-3xl font-bold mt-2">{peakRssi} <span className="text-base">dBm</span></p></Card>
        </div>
        <Card className="flex-1 flex flex-col p-0">
             <div className="grid grid-cols-12 gap-4 items-center px-4 py-2 font-bold text-xs text-tesla-text uppercase border-b border-tesla-border">
                <div className="col-span-1">#</div><div className="col-span-6">EPC</div><div className="col-span-3">Signal</div><div className="col-span-1 text-center">RSSI</div><div className="col-span-1 text-center">Last Seen</div>
            </div>
            <div className="flex-1">
                <AutoSizer>{({height, width}) => <FixedSizeList height={height} width={width} itemCount={tags.length} itemSize={40} itemData={tags}>{TagRow}</FixedSizeList>}</AutoSizer>
            </div>
        </Card>
    </>;
};

const FindItemView: React.FC<{onStart:()=>void, onStop:()=>void, isScanning:boolean, targetEpc:string, setTargetEpc:(s:string)=>void, rssi:number|null, lastSeen:number}> =
({onStart, onStop, isScanning, targetEpc, setTargetEpc, rssi, lastSeen}) => {
    const [strength, setStrength] = useState(0);
    useEffect(() => {
        let decayTimer: number;
        if(rssi !== null) {
            setStrength(Math.max(0, Math.min(100, ((rssi + 90) / 60) * 100)));
        }
        const checkDecay = () => {
            if(Date.now() - lastSeen > 2000) {
                setStrength(s => Math.max(0, s-2));
            }
            decayTimer = requestAnimationFrame(checkDecay);
        }
        decayTimer = requestAnimationFrame(checkDecay);
        return () => cancelAnimationFrame(decayTimer);
    }, [rssi, lastSeen]);

    return <Card className="max-w-md mx-auto flex flex-col items-center gap-6">
        <h2 className="text-lg font-bold">Find Item</h2>
        <input type="text" placeholder="Enter Target EPC" value={targetEpc} onChange={e => setTargetEpc(e.target.value.toUpperCase())} className="w-full text-center p-2 border rounded-lg font-mono"/>
        <div className="w-full h-16 bg-gray-200 rounded-lg overflow-hidden"><div className="h-full bg-tesla-blue transition-all duration-100" style={{width: `${strength}%`}}></div></div>
        <div className="text-center">
            <p className="text-tesla-text">Signal</p>
            <p className="text-4xl font-bold">{rssi !== null && strength > 0 ? `${rssi} dBm` : '---'}</p>
        </div>
        { isScanning ? <Button variant="danger" onClick={onStop}>Stop Finding</Button> : <Button variant="primary" onClick={onStart} disabled={!targetEpc}>Start Finding</Button> }
    </Card>;
};

const TagEncoderView: React.FC<{onScan:()=>void, isScanning:boolean, tags:Tag[], onWrite:(old:string,neu:string)=>void, writeStatus:WriteStatus, writeMessage:string}> =
({onScan, isScanning, tags, onWrite, writeStatus, writeMessage}) => {
    const [currentEpc, setCurrentEpc] = useState('');
    const [newEpc, setNewEpc] = useState('');

    const statusColors = { idle: '', pending: 'text-gray-500', success: 'text-tesla-green', error: 'text-tesla-red' };

    return <div className="grid grid-cols-1 md:grid-cols-2 gap-6 h-full">
        <Card className="flex flex-col">
            <h2 className="text-lg font-bold">1. Scan Nearby</h2>
            <Button onClick={onScan} disabled={isScanning} className="my-4">{isScanning ? <LoaderCircle className="animate-spin"/> : 'Scan for Tags (3s)'}</Button>
            <div className="flex-1 border rounded-lg overflow-y-auto">
                {tags.map(t => <div key={t.epc} onClick={() => setCurrentEpc(t.epc)} className={`p-2 font-mono text-sm cursor-pointer hover:bg-gray-100 ${currentEpc === t.epc ? 'bg-tesla-blue text-white' : ''}`}>{t.epc}</div>)}
            </div>
        </Card>
        <Card>
             <h2 className="text-lg font-bold">2. Write New EPC</h2>
             <div className="space-y-4 my-4">
                <div><label className="font-semibold text-sm text-tesla-text">Current EPC</label><input readOnly value={currentEpc} className="w-full p-2 border rounded-lg font-mono bg-gray-100"/></div>
                <div><label className="font-semibold text-sm text-tesla-text">New EPC (24 Hex Chars)</label><input value={newEpc} onChange={e=>setNewEpc(e.target.value.toUpperCase())} maxLength={24} className="w-full p-2 border rounded-lg font-mono"/></div>
             </div>
             <Button onClick={() => onWrite(currentEpc, newEpc)} disabled={!currentEpc || !newEpc || writeStatus === 'pending'}>{writeStatus === 'pending' ? <LoaderCircle className="animate-spin"/> : 'Write Tag'}</Button>
             {writeMessage && <p className={`mt-4 text-sm font-semibold ${statusColors[writeStatus]}`}>
                {writeStatus === 'success' && <CheckCircle className="inline mr-2"/>}
                {writeStatus === 'error' && <XCircle className="inline mr-2"/>}
                {writeMessage}
             </p>}
        </Card>
    </div>;
};

const SettingsView: React.FC<{ settings: Settings; onUpdate: (key: keyof Settings, value: any) => void }> = ({ settings, onUpdate }) => {
    const [rf, setRf] = useState({ speed: '1', q: '4', session: '1', target: '0' });
    useEffect(() => {
        const [speed, q, session, target] = settings.rfParams.split(',');
        setRf({ speed, q, session, target });
    }, [settings.rfParams]);

    const handleRfChange = (part: 'speed'|'q'|'session'|'target', value: string) => {
        const newRf = {...rf, [part]: value};
        setRf(newRf);
        onUpdate('rfParams', `${newRf.speed},${newRf.q},${newRf.session},${newRf.target}`);
    };

    return <div className="max-w-2xl mx-auto space-y-6">
        <Card>
            <h2 className="text-lg font-bold mb-4">Device Info</h2>
            <p className="font-mono text-tesla-text">{settings.deviceInfo}</p>
        </Card>
        <Card className="space-y-4">
            <h2 className="text-lg font-bold">Configuration</h2>
            <div className="flex justify-between items-center"><label>RF Power ({settings.power} dBm)</label><input type="range" min="0" max="33" value={settings.power} onChange={e => onUpdate('power', parseInt(e.target.value))} /></div>
            <div className="flex justify-between items-center"><label>Region</label><select value={settings.frequency} onChange={e => onUpdate('frequency', e.target.value)} className="p-2 border rounded-lg"><option value="US">FCC (US)</option><option value="EU">ETSI (EU)</option></select></div>
            <div className="flex justify-between items-center"><label>Buzzer</label><Toggle checked={settings.buzzer} onChange={v => onUpdate('buzzer', v)}/></div>
        </Card>
        <Card className="space-y-4">
            <h2 className="text-lg font-bold">Advanced Baseband</h2>
            <div className="flex justify-between items-center"><label>Q-Value</label><select value={rf.q} onChange={e => handleRfChange('q', e.target.value)} className="p-2 border rounded-lg">{Array.from({length:16}, (_,i)=>i).map(i=><option key={i} value={i}>{i}</option>)}</select></div>
            <div className="flex justify-between items-center"><label>Session</label><select value={rf.session} onChange={e => handleRfChange('session', e.target.value)} className="p-2 border rounded-lg"><option value="0">S0</option><option value="1">S1</option><option value="2">S2</option><option value="3">S3</option></select></div>
        </Card>
    </div>;
};

export default App;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { bleService } from './services/bleService';
import { ConnectionStatus, ActiveView, Tag, Settings, WriteStatus } from './types';
import { Wifi, Search, Pencil, Settings as SettingsIcon, Rss, BarChart, Hash, Cpu, LoaderCircle, CheckCircle, XCircle, Copy } from 'lucide-react';
import { Logo } from './components/ui/Logo';
import AutoSizer from 'react-virtualized-auto-sizer';
import { FixedSizeList } from 'react-window';

// --- UI COMPONENTS (Defined in-file for simplicity) ---

const Card: React.FC<{ children: React.ReactNode; className?: string }> = ({ children, className }) => (
  <div className={`bg-tesla-card rounded-2xl border border-tesla-border shadow-sm p-6 ${className}`}>{children}</div>
);

const Button: React.FC<React.ButtonHTMLAttributes<HTMLButtonElement> & { variant?: 'primary' | 'secondary' | 'danger' }> = ({ children, className, variant = 'primary', ...props }) => {
  const variants = {
    primary: 'bg-tesla-blue text-white hover:bg-opacity-90',
    secondary: 'bg-gray-200 text-tesla-heading hover:bg-gray-300',
    danger: 'bg-tesla-red text-white hover:bg-opacity-90',
  };
  return <button className={`px-4 py-2 rounded-lg font-semibold text-sm transition-all ${variants[variant]} disabled:opacity-50 ${className}`} {...props}>{children}</button>;
};

const Toggle: React.FC<{ checked: boolean; onChange: (checked: boolean) => void }> = ({ checked, onChange }) => (
  <button onClick={() => onChange(!checked)} className={`relative w-12 h-6 rounded-full transition-colors ${checked ? 'bg-tesla-blue' : 'bg-gray-300'}`}>
    <span className={`absolute left-1 top-1 w-4 h-4 bg-white rounded-full transition-transform ${checked ? 'transform translate-x-6' : ''}`} />
  </button>
);

// --- MAIN APP ---

function App() {
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [activeView, setActiveView] = useState<ActiveView>('monitor');
  const [isScanning, setIsScanning] = useState(false);
  const [settings, setSettings] = useState<Settings>({ power: 33, frequency: 'US', rfParams: '1,4,1,0', buzzer: true, deviceInfo: 'N/A' });
  const [tags, setTags] = useState<Map<string, Tag>>(new Map());
  const [readRate, setReadRate] = useState(0);

  // Encoder State
  const [encoderScanTags, setEncoderScanTags] = useState<Tag[]>([]);
  const [isEncoderScanning, setIsEncoderScanning] = useState(false);
  const [writeStatus, setWriteStatus] = useState<WriteStatus>('idle');
  const [writeMessage, setWriteMessage] = useState('');

  // Find State
  const [targetEpc, setTargetEpc] = useState('');
  const [foundTagRssi, setFoundTagRssi] = useState<number | null>(null);
  const [lastRssiUpdate, setLastRssiUpdate] = useState(0);

  const tagsReadInSecond = useRef(0);

  const handleDataReceived = useCallback((data: any) => {
    // Tag Data
    if (data.cmd === 'live_tags' && Array.isArray(data.tags)) {
      setTags(prevTags => {
        const newTags = new Map(prevTags);
        let targetFound = false;
        data.tags.forEach((tag: { e?: string; r?: number }) => {
          if (!tag.e) return;
          tagsReadInSecond.current++;
          const existing = newTags.get(tag.e);
          if (existing) {
            existing.count += 1;
            existing.rssi = tag.r;
            existing.timestamp = Date.now();
          } else {
            newTags.set(tag.e, { epc: tag.e, timestamp: Date.now(), rssi: tag.r, count: 1 });
          }
          if (tag.e === targetEpc) {
            setFoundTagRssi(tag.r ?? null);
            setLastRssiUpdate(Date.now());
            targetFound = true;
          }
        });
        if (!targetFound && activeView === 'find') {
            // Let Geiger decay logic handle it
        }
        return newTags;
      });
    }
    // Settings Responses
    if (data.cmd === 'DI') setSettings(s => ({ ...s, deviceInfo: data.val }));
    if (data.cmd === 'GP') setSettings(s => ({ ...s, power: data.val }));
    if (data.cmd === 'GF') setSettings(s => ({ ...s, frequency: data.val }));
    if (data.cmd === 'GRP') setSettings(s => ({ ...s, rfParams: data.val }));
    // Write Response
    if (data.cmd === 'WE') {
      if (data.status === 'ok') {
        setWriteStatus('success');
        setWriteMessage(`Success! New EPC: ${data.epc}`);
      } else {
        setWriteStatus('error');
        setWriteMessage(data.error || 'Write failed. Tag may be out of range.');
      }
    }
  }, [activeView, targetEpc]);

  useEffect(() => {
    bleService.setCallbacks(handleDataReceived, (msg, type) => console.log(`[${type}] ${msg}`));
    const rateInterval = setInterval(() => {
      setReadRate(tagsReadInSecond.current);
      tagsReadInSecond.current = 0;
    }, 1000);
    return () => clearInterval(rateInterval);
  }, [handleDataReceived]);

  const handleConnect = async () => {
    try {
      setStatus(ConnectionStatus.CONNECTING);
      await bleService.connect();
      setStatus(ConnectionStatus.CONNECTED);
      setTimeout(() => bleService.getSettings(), 500);
    } catch (e) {
      setStatus(ConnectionStatus.ERROR);
    }
  };

  const handleDisconnect = () => {
    bleService.disconnect();
    setStatus(ConnectionStatus.DISCONNECTED);
    setIsScanning(false);
    setTags(new Map());
  };

  const handleStartScan = async (mode: 'live' | 'find' | 'encoder') => {
    if (status !== ConnectionStatus.CONNECTED || isScanning) return;
    setIsScanning(true);
    setTags(new Map());

    let cmd: object = { cmd: 'S' };
    if(mode === 'find' && targetEpc) {
        cmd = { cmd: 'F', val: targetEpc };
    }

    if (mode === 'encoder') {
      setIsEncoderScanning(true);
      setEncoderScanTags([]);
      const encoderListener = (data: any) => {
        if (data.cmd === 'live_tags') {
          setEncoderScanTags(prev => {
            const newTags = [...prev];
            data.tags.forEach((t: any) => {
              if(!newTags.find(et => et.epc === t.e)) {
                newTags.push({epc: t.e, rssi: t.r, count: 1, timestamp: Date.now()});
              }
            });
            return newTags;
          });
        }
      };
      bleService.setCallbacks(encoderListener, (msg, type) => console.log(msg));
      await bleService.sendCommand({ cmd: 'S' });
      setTimeout(async () => {
        await bleService.sendCommand({ cmd: 'X' });
        setIsEncoderScanning(false);
        bleService.setCallbacks(handleDataReceived, (msg, type) => console.log(msg));
      }, 3000); // 3-second scan
      return;
    }

    await bleService.sendCommand(cmd);
  };

  const handleStopScan = async () => {
    if (status !== ConnectionStatus.CONNECTED) return;
    await bleService.sendCommand({ cmd: 'X' });
    setIsScanning(false);
  };

  const handleUpdateSetting = async (key: keyof Settings, value: any) => {
    // Optimistically update UI
    setSettings(s => ({...s, [key]: value}));
    let cmd = {};
    if (key === 'power') cmd = {cmd: 'SP', val: value};
    if (key === 'frequency') cmd = {cmd: 'SF', val: value};
    if (key === 'buzzer') cmd = {cmd: 'BZ', val: value ? 'on' : 'off'};
    if (key === 'rfParams') cmd = {cmd: 'SRP', val: value};
    await bleService.sendCommand(cmd);
    // After sending, refresh settings from device to confirm
    setTimeout(() => bleService.getSettings(), 200);
  }

  const handleWrite = async (oldEpc: string, newEpc: string) => {
    if (!oldEpc || !newEpc || newEpc.length !== 24 || !/^[0-9A-F]*$/i.test(newEpc)) {
        setWriteStatus('error');
        setWriteMessage('Invalid EPC format. Must be 24 hex characters.');
        return;
    }
    setWriteStatus('pending');
    setWriteMessage('');
    await bleService.sendCommand({ cmd: 'WE', old: oldEpc, new: newEpc });
    setTimeout(() => { if(writeStatus === 'pending') setWriteStatus('idle'); }, 5000); // Timeout
  }

  const sortedTags = useMemo(() => Array.from(tags.values()).sort((a, b) => b.timestamp - a.timestamp), [tags]);
  const peakRssi = useMemo(() => sortedTags.length > 0 ? Math.max(...sortedTags.map(t => t.rssi ?? -100)) : '-', [sortedTags]);

  const renderView = () => {
    switch (activeView) {
      case 'monitor': return <LiveMonitorView tags={sortedTags} peakRssi={peakRssi} readRate={readRate} totalTags={tags.size} />;
      case 'find': return <FindItemView onStart={() => handleStartScan('find')} onStop={handleStopScan} isScanning={isScanning} targetEpc={targetEpc} setTargetEpc={setTargetEpc} rssi={foundTagRssi} lastSeen={lastRssiUpdate} />;
      case 'encoder': return <TagEncoderView onScan={() => handleStartScan('encoder')} isScanning={isEncoderScanning} tags={encoderScanTags} onWrite={handleWrite} writeStatus={writeStatus} writeMessage={writeMessage} />;
      case 'settings': return <SettingsView settings={settings} onUpdate={handleUpdateSetting} />;
      default: return null;
    }
  };

  return (
    <div className="fixed inset-0 flex bg-tesla-bg text-tesla-heading font-sans">
      <Sidebar activeView={activeView} setActiveView={setActiveView} />
      <main className="flex-1 flex flex-col">
        <Header status={status} onConnect={handleConnect} onDisconnect={handleDisconnect} isScanning={isScanning} onStartScan={() => handleStartScan('live')} onStopScan={handleStopScan} activeView={activeView} />
        <div className="flex-1 overflow-y-auto p-6">{renderView()}</div>
      </main>
    </div>
  );
}

// --- SUB-COMPONENTS FOR VIEWS ---

const Sidebar: React.FC<{ activeView: ActiveView; setActiveView: (v: ActiveView) => void }> = ({ activeView, setActiveView }) => {
  const NavItem = ({ icon: Icon, label, view }: { icon: any; label: string; view: ActiveView }) => (
    <button onClick={() => setActiveView(view)} className={`flex flex-col items-center justify-center gap-1 w-full aspect-square rounded-lg transition-colors ${activeView === view ? 'bg-black/5 text-tesla-blue' : 'text-tesla-text hover:bg-black/5'}`}>
      <Icon size={24} />
      <span className="text-xs font-semibold">{label}</span>
    </button>
  );
  return (
    <aside className="w-24 bg-tesla-card border-r border-tesla-border flex flex-col items-center p-3 gap-2">
      <Logo className="w-12 h-12 mb-4" />
      <NavItem icon={Rss} label="Monitor" view="monitor" />
      <NavItem icon={Search} label="Find" view="find" />
      <NavItem icon={Pencil} label="Encoder" view="encoder" />
      <NavItem icon={SettingsIcon} label="Settings" view="settings" />
    </aside>
  );
};

const Header: React.FC<{ status: ConnectionStatus; onConnect: () => void; onDisconnect: () => void; isScanning: boolean; onStartScan: () => void; onStopScan: () => void, activeView: ActiveView }> = 
({ status, onConnect, onDisconnect, isScanning, onStartScan, onStopScan, activeView }) => (
  <header className="h-20 bg-tesla-card border-b border-tesla-border flex items-center justify-between px-6 flex-shrink-0">
    <div>
      <h1 className="text-2xl font-bold text-tesla-heading capitalize">{activeView}</h1>
    </div>
    <div className="flex items-center gap-4">
      {activeView === 'monitor' && (
        isScanning ? <Button variant="danger" onClick={onStopScan}>Stop Stream</Button> : <Button variant="primary" onClick={onStartScan} disabled={status !== ConnectionStatus.CONNECTED}>Start Stream</Button>
      )}
      <Button variant="secondary" onClick={status === ConnectionStatus.CONNECTED ? onDisconnect : onConnect} disabled={status === ConnectionStatus.CONNECTING}>
        {status === ConnectionStatus.CONNECTING ? <LoaderCircle className="animate-spin"/> : status === ConnectionStatus.CONNECTED ? 'Disconnect' : 'Connect'}
      </Button>
    </div>
  </header>
);

const LiveMonitorView: React.FC<{ tags: Tag[], totalTags: number, readRate: number, peakRssi: number | string }> = ({ tags, totalTags, readRate, peakRssi }) => {
    const TagRow = ({ index, style, data }: { index: number; style: React.CSSProperties; data: Tag[] }) => {
        const tag = data[index];
        const rssiStrength = tag.rssi ? Math.max(0, Math.min(100, ((tag.rssi + 90) / 60) * 100)) : 0;
        return (
            <div style={style} className="grid grid-cols-12 gap-4 items-center px-4 font-mono text-sm border-b border-tesla-border">
                <div className="col-span-1 text-tesla-text">{index + 1}</div>
                <div className="col-span-6 truncate">{tag.epc}</div>
                <div className="col-span-3">
                    <div className="w-full bg-gray-200 rounded-full h-2"><div className="bg-tesla-blue h-2 rounded-full" style={{width: `${rssiStrength}%`}}></div></div>
                </div>
                <div className="col-span-1 text-center">{tag.rssi ?? '-'}</div>
                <div className="col-span-1 text-center">{new Date(tag.timestamp).toLocaleTimeString()}</div>
            </div>
        );
    };

    return <>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-6">
            <Card><h3 className="text-tesla-text text-sm font-semibold">Total Tags</h3><p className="text-3xl font-bold mt-2">{totalTags}</p></Card>
            <Card><h3 className="text-tesla-text text-sm font-semibold">Read Rate</h3><p className="text-3xl font-bold mt-2">{readRate} <span className="text-base">tags/s</span></p></Card>
            <Card><h3 className="text-tesla-text text-sm font-semibold">Peak RSSI</h3><p className="text-3xl font-bold mt-2">{peakRssi} <span className="text-base">dBm</span></p></Card>
        </div>
        <Card className="flex-1 flex flex-col p-0">
             <div className="grid grid-cols-12 gap-4 items-center px-4 py-2 font-bold text-xs text-tesla-text uppercase border-b border-tesla-border">
                <div className="col-span-1">#</div><div className="col-span-6">EPC</div><div className="col-span-3">Signal</div><div className="col-span-1 text-center">RSSI</div><div className="col-span-1 text-center">Last Seen</div>
            </div>
            <div className="flex-1">
                <AutoSizer>{({height, width}) => <FixedSizeList height={height} width={width} itemCount={tags.length} itemSize={40} itemData={tags}>{TagRow}</FixedSizeList>}</AutoSizer>
            </div>
        </Card>
    </>;
};

const FindItemView: React.FC<{onStart:()=>void, onStop:()=>void, isScanning:boolean, targetEpc:string, setTargetEpc:(s:string)=>void, rssi:number|null, lastSeen:number}> =
({onStart, onStop, isScanning, targetEpc, setTargetEpc, rssi, lastSeen}) => {
    const [strength, setStrength] = useState(0);
    useEffect(() => {
        let decayTimer: number;
        if(rssi !== null) {
            setStrength(Math.max(0, Math.min(100, ((rssi + 90) / 60) * 100)));
        }
        const checkDecay = () => {
            if(Date.now() - lastSeen > 2000) {
                setStrength(s => Math.max(0, s-2));
            }
            decayTimer = requestAnimationFrame(checkDecay);
        }
        decayTimer = requestAnimationFrame(checkDecay);
        return () => cancelAnimationFrame(decayTimer);
    }, [rssi, lastSeen]);

    return <Card className="max-w-md mx-auto flex flex-col items-center gap-6">
        <h2 className="text-lg font-bold">Find Item</h2>
        <input type="text" placeholder="Enter Target EPC" value={targetEpc} onChange={e => setTargetEpc(e.target.value.toUpperCase())} className="w-full text-center p-2 border rounded-lg font-mono"/>
        <div className="w-full h-16 bg-gray-200 rounded-lg overflow-hidden"><div className="h-full bg-tesla-blue transition-all duration-100" style={{width: `${strength}%`}}></div></div>
        <div className="text-center">
            <p className="text-tesla-text">Signal</p>
            <p className="text-4xl font-bold">{rssi !== null && strength > 0 ? `${rssi} dBm` : '---'}</p>
        </div>
        { isScanning ? <Button variant="danger" onClick={onStop}>Stop Finding</Button> : <Button variant="primary" onClick={onStart} disabled={!targetEpc}>Start Finding</Button> }
    </Card>;
};

const TagEncoderView: React.FC<{onScan:()=>void, isScanning:boolean, tags:Tag[], onWrite:(old:string,neu:string)=>void, writeStatus:WriteStatus, writeMessage:string}> =
({onScan, isScanning, tags, onWrite, writeStatus, writeMessage}) => {
    const [currentEpc, setCurrentEpc] = useState('');
    const [newEpc, setNewEpc] = useState('');

    const statusColors = { idle: '', pending: 'text-gray-500', success: 'text-tesla-green', error: 'text-tesla-red' };

    return <div className="grid grid-cols-1 md:grid-cols-2 gap-6 h-full">
        <Card className="flex flex-col">
            <h2 className="text-lg font-bold">1. Scan Nearby</h2>
            <Button onClick={onScan} disabled={isScanning} className="my-4">{isScanning ? <LoaderCircle className="animate-spin"/> : 'Scan for Tags (3s)'}</Button>
            <div className="flex-1 border rounded-lg overflow-y-auto">
                {tags.map(t => <div key={t.epc} onClick={() => setCurrentEpc(t.epc)} className={`p-2 font-mono text-sm cursor-pointer hover:bg-gray-100 ${currentEpc === t.epc ? 'bg-tesla-blue text-white' : ''}`}>{t.epc}</div>)}
            </div>
        </Card>
        <Card>
             <h2 className="text-lg font-bold">2. Write New EPC</h2>
             <div className="space-y-4 my-4">
                <div><label className="font-semibold text-sm text-tesla-text">Current EPC</label><input readOnly value={currentEpc} className="w-full p-2 border rounded-lg font-mono bg-gray-100"/></div>
                <div><label className="font-semibold text-sm text-tesla-text">New EPC (24 Hex Chars)</label><input value={newEpc} onChange={e=>setNewEpc(e.target.value.toUpperCase())} maxLength={24} className="w-full p-2 border rounded-lg font-mono"/></div>
             </div>
             <Button onClick={() => onWrite(currentEpc, newEpc)} disabled={!currentEpc || !newEpc || writeStatus === 'pending'}>{writeStatus === 'pending' ? <LoaderCircle className="animate-spin"/> : 'Write Tag'}</Button>
             {writeMessage && <p className={`mt-4 text-sm font-semibold ${statusColors[writeStatus]}`}>
                {writeStatus === 'success' && <CheckCircle className="inline mr-2"/>}
                {writeStatus === 'error' && <XCircle className="inline mr-2"/>}
                {writeMessage}
             </p>}
        </Card>
    </div>;
};

const SettingsView: React.FC<{ settings: Settings; onUpdate: (key: keyof Settings, value: any) => void }> = ({ settings, onUpdate }) => {
    const [localSettings, setLocalSettings] = useState(settings);

    useEffect(() => {
        setLocalSettings(settings);
    }, [settings]);

    const handleRfChange = (part: 'q'|'session', value: string) => {
        const rfParts = localSettings.rfParams.split(',');
        const rfMap = { speed: 0, q: 1, session: 2, target: 3 };
        rfParts[rfMap[part]] = value;
        setLocalSettings(s => ({ ...s, rfParams: rfParts.join(',') }));
    };

    const rf = useMemo(() => {
        const [speed = '1', q = '4', session = '1', target = '0'] = localSettings.rfParams.split(',');
        return { speed, q, session, target };
    }, [localSettings.rfParams]);

    const isConfigDirty = localSettings.power !== settings.power || localSettings.frequency !== settings.frequency || localSettings.buzzer !== settings.buzzer;
    const isBasebandDirty = localSettings.rfParams !== settings.rfParams;

    const handleApplyConfig = () => {
        if (localSettings.power !== settings.power) onUpdate('power', localSettings.power);
        if (localSettings.frequency !== settings.frequency) onUpdate('frequency', localSettings.frequency);
        if (localSettings.buzzer !== settings.buzzer) onUpdate('buzzer', localSettings.buzzer);
    };

    const handleApplyBaseband = () => {
        if (localSettings.rfParams !== settings.rfParams) onUpdate('rfParams', localSettings.rfParams);
    };

    return <div className="max-w-2xl mx-auto space-y-6">
        <Card>
            <h2 className="text-lg font-bold mb-4">Device Info</h2>
            <p className="font-mono text-tesla-text p-3 bg-gray-100 rounded-lg">{settings.deviceInfo}</p>
        </Card>
        <Card>
            <div className="flex justify-between items-center mb-6">
                 <h2 className="text-lg font-bold">Configuration</h2>
                 {isConfigDirty && <Button variant="primary" onClick={handleApplyConfig} className="text-xs px-3 py-1">Apply</Button>}
            </div>
            <div className="space-y-5">
                <div className="flex justify-between items-center">
                    <label className="font-medium text-tesla-text">RF Power ({localSettings.power} dBm)</label>
                    <input type="range" min="0" max="33" value={localSettings.power} onChange={e => setLocalSettings(s => ({...s, power: parseInt(e.target.value)}))} className="w-48 accent-tesla-blue" />
                </div>
                <div className="flex justify-between items-center">
                    <label className="font-medium text-tesla-text">Region</label>
                    <select value={localSettings.frequency} onChange={e => setLocalSettings(s => ({...s, frequency: e.target.value}))} className="p-2 border rounded-lg bg-gray-50 border-tesla-border text-sm font-medium">
                        <option value="US">FCC (US)</option>
                        <option value="EU">ETSI (EU)</option>
                    </select>
                </div>
                <div className="flex justify-between items-center">
                    <label className="font-medium text-tesla-text">Buzzer</label>
                    <Toggle checked={localSettings.buzzer} onChange={v => setLocalSettings(s => ({...s, buzzer: v}))}/>
                </div>
            </div>
        </Card>
        <Card>
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-lg font-bold">Advanced Baseband</h2>
                {isBasebandDirty && <Button variant="primary" onClick={handleApplyBaseband} className="text-xs px-3 py-1">Apply</Button>}
            </div>
            <div className="space-y-5">
                <div className="flex justify-between items-center">
                    <label className="font-medium text-tesla-text">Q-Value</label>
                    <select value={rf.q} onChange={e => handleRfChange('q', e.target.value)} className="p-2 border rounded-lg bg-gray-50 border-tesla-border text-sm font-medium">
                        {Array.from({length:16}, (_,i)=>i).map(i=><option key={i} value={i}>{i}</option>)}
                    </select>
                </div>
                <div className="flex justify-between items-center">
                    <label className="font-medium text-tesla-text">Session</label>
                    <select value={rf.session} onChange={e => handleRfChange('session', e.target.value)} className="p-2 border rounded-lg bg-gray-50 border-tesla-border text-sm font-medium">
                        <option value="0">S0</option><option value="1">S1</option><option value="2">S2</option><option value="3">S3</option>
                    </select>
                </div>
            </div>
        </Card>
    </div>;
};

export default App;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { bleService } from './services/bleService';
import { ConnectionStatus, ActiveView, Tag, Settings, WriteStatus } from './types';
import { 
  Wifi, Search, Pencil, Settings as SettingsIcon, Rss, 
  BarChart, Hash, Cpu, LoaderCircle, CheckCircle, XCircle, 
  Copy, Battery, Thermometer, ChevronRight, Save, Play, Square
} from 'lucide-react';
import { Logo } from './components/ui/Logo';
import AutoSizer from 'react-virtualized-auto-sizer';
import { FixedSizeList } from 'react-window';

// --- UI COMPONENTS ---

const Card: React.FC<{ children: React.ReactNode; className?: string; title?: string; action?: React.ReactNode }> = ({ children, className, title, action }) => (
  <div className={`bg-white rounded-2xl border border-gray-200 shadow-sm overflow-hidden ${className}`}>
    {(title || action) && (
      <div className="px-6 py-4 border-b border-gray-100 flex justify-between items-center bg-gray-50/50">
        {title && <h3 className="font-semibold text-gray-900">{title}</h3>}
        {action && <div>{action}</div>}
      </div>
    )}
    <div className="p-6">{children}</div>
  </div>
);

const Button: React.FC<React.ButtonHTMLAttributes<HTMLButtonElement> & { variant?: 'primary' | 'secondary' | 'danger' | 'ghost' }> = ({ children, className, variant = 'primary', ...props }) => {
  const variants = {
    primary: 'bg-tesla-blue text-white hover:bg-blue-600 shadow-sm',
    secondary: 'bg-gray-100 text-gray-900 hover:bg-gray-200',
    danger: 'bg-red-500 text-white hover:bg-red-600 shadow-sm',
    ghost: 'bg-transparent text-gray-500 hover:bg-gray-100',
  };
