        )}
        <Button variant={status === ConnectionStatus.CONNECTED ? "secondary" : "primary"} onClick={status === ConnectionStatus.CONNECTED ? onDisconnect : onConnect} disabled={status === ConnectionStatus.CONNECTING} className="h-9">
            {status === ConnectionStatus.CONNECTING ? <LoaderCircle size={14} className="animate-spin"/> : status === ConnectionStatus.CONNECTED ? 'Disconnect' : 'Connect'}
