const LiveMonitorView: React.FC<{ tags: Tag[], totalTags: number, readRate: number, peakRssi: number | string }> = ({ tags, totalTags, readRate, peakRssi }) => {
    const TagRow = ({ index, style, data }: { index: number; style: React.CSSProperties; data: Tag[] }) => {
        const tag = data[index];
        const rssiPercent = tag.rssi ? Math.max(0, Math.min(100, ((tag.rssi + 90) / 60) * 100)) : 0;
        return (
            <div style={style} className="grid grid-cols-12 gap-4 items-center px-6 text-sm border-b border-gray-100 hover:bg-gray-50 transition-colors">
                <div className="col-span-1 text-gray-400 font-mono text-xs">{index + 1}</div>
                <div className="col-span-5 font-mono text-gray-700 truncate font-medium">{tag.epc}</div>
                <div className="col-span-3 pr-4">
                    <div className="w-full bg-gray-100 rounded-full h-1.5 overflow-hidden">
                        <div className={`h-full rounded-full transition-all duration-300 ${rssiPercent > 70 ? 'bg-emerald-500' : rssiPercent > 40 ? 'bg-amber-500' : 'bg-red-500'}`} style={{width: `${rssiPercent}%`}}></div>
                    </div>
                </div>
                <div className="col-span-1 text-right font-mono text-gray-600">{tag.rssi}</div>
                <div className="col-span-2 text-right text-gray-400 text-xs">{new Date(tag.timestamp).toLocaleTimeString()}</div>
            </div>
        );
    };

    return <>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-6">
            <Card className="p-5 flex items-center justify-between">
                 <div><p className="text-gray-500 text-xs font-semibold uppercase tracking-wider">Total Tags</p><p className="text-3xl font-bold text-gray-900 mt-1">{totalTags}</p></div>
                 <Hash className="text-gray-300" size={32} />
            </Card>
            <Card className="p-5 flex items-center justify-between">
                 <div><p className="text-gray-500 text-xs font-semibold uppercase tracking-wider">Read Rate</p><p className="text-3xl font-bold text-gray-900 mt-1">{readRate} <span className="text-sm font-normal text-gray-400">t/s</span></p></div>
                 <Cpu className="text-gray-300" size={32} />
            </Card>
             <Card className="p-5 flex items-center justify-between">
                 <div><p className="text-gray-500 text-xs font-semibold uppercase tracking-wider">Peak RSSI</p><p className="text-3xl font-bold text-gray-900 mt-1">{peakRssi} <span className="text-sm font-normal text-gray-400">dBm</span></p></div>
                 <Wifi className="text-gray-300" size={32} />
            </Card>
        </div>
        <Card className="flex-1 flex flex-col p-0 border-gray-200 overflow-hidden shadow-sm">
             <div className="grid grid-cols-12 gap-4 items-center px-6 py-3 bg-gray-50/80 border-b border-gray-200 text-xs font-bold text-gray-500 uppercase tracking-wider backdrop-blur-sm sticky top-0 z-10">
                <div className="col-span-1">#</div><div className="col-span-5">EPC</div><div className="col-span-3">Signal Quality</div><div className="col-span-1 text-right">dBm</div><div className="col-span-2 text-right">Time</div>
            </div>
            <div className="flex-1 bg-white">
                <AutoSizer>{({height, width}) => <FixedSizeList height={height} width={width} itemCount={tags.length} itemSize={48} itemData={tags}>{TagRow}</FixedSizeList>}</AutoSizer>
            </div>
        </Card>
    </>;
};

const FindItemView: React.FC<{onStart:()=>void, onStop:()=>void, isScanning:boolean, targetEpc:string, setTargetEpc:(s:string)=>void, rssi:number|null, lastSeen:number}> =
({onStart, onStop, isScanning, targetEpc, setTargetEpc, rssi, lastSeen}) => {
    const [strength, setStrength] = useState(0);
    useEffect(() => {
        let decayTimer: number;
        if(rssi !== null) {
            setStrength(Math.max(0, Math.min(100, ((rssi + 90) / 60) * 100)));
        }
        const checkDecay = () => {
            if(Date.now() - lastSeen > 2000) setStrength(s => Math.max(0, s-2));
            decayTimer = requestAnimationFrame(checkDecay);
        }
        decayTimer = requestAnimationFrame(checkDecay);
        return () => cancelAnimationFrame(decayTimer);
    }, [rssi, lastSeen]);

    return <div className="max-w-2xl mx-auto py-10 space-y-8">
        <Card className="p-8 flex flex-col items-center gap-8 text-center">
            <div className="space-y-2">
                <h2 className="text-2xl font-bold text-gray-900">Geiger Search</h2>
                <p className="text-gray-500">Enter a target EPC to track its signal strength in real-time.</p>
            </div>

            <div className="w-full max-w-md relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={20}/>
                <input type="text" placeholder="Paste Target EPC..." value={targetEpc} onChange={e => setTargetEpc(e.target.value.toUpperCase())} className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl font-mono text-lg focus:ring-2 focus:ring-tesla-blue focus:border-transparent transition-all"/>
            </div>

            <div className="w-full max-w-lg space-y-2">
                 <div className="flex justify-between text-xs font-bold text-gray-400 uppercase tracking-wider">
                    <span>Weak Signal</span>
                    <span>Strong Signal</span>
                 </div>
                 <div className="h-16 bg-gray-100 rounded-2xl overflow-hidden p-1 shadow-inner">
                    <div 
                        className={`h-full rounded-xl transition-all duration-150 ease-out shadow-sm ${strength > 0 ? 'opacity-100' : 'opacity-0'} ${strength > 70 ? 'bg-gradient-to-r from-emerald-400 to-emerald-500' : strength > 40 ? 'bg-gradient-to-r from-amber-400 to-amber-500' : 'bg-gradient-to-r from-red-400 to-red-500'}`} 
                        style={{width: `${strength}%`}}
                    ></div>
                 </div>
            </div>

            <div className="grid grid-cols-2 gap-8 w-full max-w-sm">
                 <div className="text-center p-4 bg-gray-50 rounded-xl border border-gray-100">
                    <p className="text-xs text-gray-500 uppercase tracking-wider font-semibold">Signal</p>
                    <p className="text-3xl font-bold text-gray-900 mt-1">{rssi !== null && strength > 0 ? `${rssi}` : '--'}<span className="text-sm font-normal text-gray-400 ml-1">dBm</span></p>
                 </div>
                 <div className="text-center p-4 bg-gray-50 rounded-xl border border-gray-100">
                    <p className="text-xs text-gray-500 uppercase tracking-wider font-semibold">Status</p>
                    <p className={`text-lg font-bold mt-2 ${strength > 0 ? 'text-green-600' : 'text-gray-400'}`}>
                        {strength > 0 ? 'DETECTED' : 'SEARCHING'}
                    </p>
                 </div>
            </div>

            <div className="w-full max-w-md">
                 { isScanning ? (
                    <Button variant="danger" onClick={onStop} className="w-full h-12 text-base shadow-red-200">Stop Search</Button>
                 ) : (
                    <Button variant="primary" onClick={onStart} disabled={!targetEpc} className="w-full h-12 text-base shadow-blue-200">Start Finding</Button>
                 )}
            </div>
        </Card>
    </div>;
};

const TagEncoderView: React.FC<{onScan:()=>void, isScanning:boolean, tags:Tag[], onWrite:(old:string,neu:string)=>void, writeStatus:WriteStatus, writeMessage:string}> =
({onScan, isScanning, tags, onWrite, writeStatus, writeMessage}) => {
    const [currentEpc, setCurrentEpc] = useState('');
    const [newEpc, setNewEpc] = useState('');

    return <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-full max-w-6xl mx-auto">
        <Card title="1. Select Source Tag" className="flex flex-col h-full" action={<Button variant="secondary" onClick={onScan} disabled={isScanning} className="text-xs">{isScanning ? <LoaderCircle className="animate-spin" size={14}/> : 'Scan Nearby (3s)'}</Button>}>
            <div className="flex-1 overflow-y-auto min-h-[300px] -mx-6 px-6">
                {tags.length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center text-gray-400 space-y-2">
                        <Search size={48} className="opacity-20"/>
                        <p>No tags scanned yet.</p>
                    </div>
                ) : (
                    <div className="space-y-2">
                         {tags.map(t => (
                            <div key={t.epc} onClick={() => setCurrentEpc(t.epc)} className={`p-3 rounded-lg border cursor-pointer transition-all flex items-center justify-between ${currentEpc === t.epc ? 'bg-blue-50 border-tesla-blue shadow-sm ring-1 ring-tesla-blue' : 'bg-white border-gray-200 hover:border-tesla-blue/50'}`}>
                                <span className="font-mono text-sm text-gray-700">{t.epc}</span>
                                <span className="text-xs font-bold text-gray-400">{t.rssi} dBm</span>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </Card>
        <Card title="2. Write New Data" className="h-fit">
             <div className="space-y-6">
                <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Target Tag (Old EPC)</label>
                    <div className="relative">
                        <input readOnly value={currentEpc} placeholder="Select a tag from list..." className="w-full p-3 bg-gray-100 border border-transparent rounded-lg font-mono text-gray-500 focus:outline-none"/>
                        {currentEpc && <CheckCircle size={18} className="absolute right-3 top-1/2 -translate-y-1/2 text-green-500"/>}
                    </div>
                </div>
                <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">New Data (New EPC)</label>
                    <input value={newEpc} onChange={e=>setNewEpc(e.target.value.toUpperCase())} maxLength={24} placeholder="Enter 24 Hex Characters" className="w-full p-3 bg-white border border-gray-300 rounded-lg font-mono text-gray-900 focus:ring-2 focus:ring-tesla-blue focus:border-transparent transition-all"/>
                    <p className="text-xs text-gray-400 mt-1 text-right">{newEpc.length}/24 chars</p>
                </div>

                <div className="pt-4 border-t border-gray-100">
                     <Button variant="primary" onClick={() => onWrite(currentEpc, newEpc)} disabled={!currentEpc || newEpc.length !== 24 || writeStatus === 'pending'} className="w-full h-12 text-base">
                        {writeStatus === 'pending' ? <LoaderCircle className="animate-spin"/> : 'Write to Tag'}
                     </Button>
                     {writeMessage && (
                        <div className={`mt-4 p-3 rounded-lg flex items-center gap-2 text-sm font-medium ${writeStatus === 'success' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                            {writeStatus === 'success' ? <CheckCircle size={18}/> : <XCircle size={18}/>}
                            {writeMessage}
                        </div>
                     )}
                </div>
             </div>
        </Card>
    </div>;
};

const SettingsView: React.FC<{ settings: Settings; onUpdate: (key: keyof Settings, value: any) => void }> = ({ settings, onUpdate }) => {
    // Local State for "Apply" Logic
    const [local, setLocal] = useState(settings);

    useEffect(() => { setLocal(settings); }, [settings]);

    // Parse Baseband String "speed,q,session,target"
    const parseRf = (str: string) => {
        const parts = str.split(',');
        return { 
            speed: parts[0] || '1', 
            q: parts[1] || '4', 
            session: parts[2] || '1', 
            target: parts[3] || '0' 
        };
    };

    const rf = useMemo(() => parseRf(local.rfParams), [local.rfParams]);

    // Check Dirty States
    const isConfigDirty = local.power !== settings.power || local.frequency !== settings.frequency || local.buzzer !== settings.buzzer;
    const isBasebandDirty = local.rfParams !== settings.rfParams;

    // Helpers
    const updateRfPart = (key: 'speed'|'q'|'session'|'target', val: string) => {
        const current = parseRf(local.rfParams);
        const next = { ...current, [key]: val };
        const nextStr = `${next.speed},${next.q},${next.session},${next.target}`;
        setLocal(s => ({ ...s, rfParams: nextStr }));
    };

    const handleApplyConfig = () => {
        if (local.power !== settings.power) onUpdate('power', local.power);
        if (local.frequency !== settings.frequency) onUpdate('frequency', local.frequency);
        if (local.buzzer !== settings.buzzer) onUpdate('buzzer', local.buzzer);
    };

    return <div className="max-w-4xl mx-auto space-y-6 pb-10">

        {/* Device Info */}
        <Card title="System Information">
             <div className="grid grid-cols-2 gap-4">
                 <div><p className="text-xs text-gray-400 uppercase tracking-wider font-semibold">Model Name</p><p className="font-mono text-gray-900 mt-1">Nextwaves Scanner V3</p></div>
                 <div><p className="text-xs text-gray-400 uppercase tracking-wider font-semibold">Firmware</p><p className="font-mono text-gray-900 mt-1">{settings.deviceInfo}</p></div>
             </div>
        </Card>

        {/* General Configuration */}
        <Card 
            title="Radio Configuration" 
            action={isConfigDirty && <Button variant="primary" onClick={handleApplyConfig} className="text-xs h-8">Apply Changes</Button>}
        >
            <div className="space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6 items-center">
                    <label className="text-sm font-medium text-gray-700">RF Output Power (dBm)</label>
                    <div className="md:col-span-2">
                        <RangeSlider min={0} max={33} value={local.power} onChange={v => setLocal(s => ({...s, power: v}))} />
                    </div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6 items-center">
                    <label className="text-sm font-medium text-gray-700">Frequency Region</label>
                    <div className="md:col-span-2">
                        <Select value={local.frequency} onChange={e => setLocal(s => ({...s, frequency: e.target.value}))}>
                            <option value="US">FCC (United States)</option>
                            <option value="EU">ETSI (Europe)</option>
                            <option value="CN">China</option>
                        </Select>
                    </div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6 items-center">
                    <label className="text-sm font-medium text-gray-700">System Buzzer</label>
                    <div className="md:col-span-2">
                        <Toggle checked={local.buzzer} onChange={v => setLocal(s => ({...s, buzzer: v}))}/>
                    </div>
                </div>
            </div>
        </Card>

        {/* Baseband Configuration */}
        <Card 
            title="Advanced Baseband" 
            action={isBasebandDirty && <Button variant="primary" onClick={() => onUpdate('rfParams', local.rfParams)} className="text-xs h-8">Apply Baseband Config</Button>}
        >
             <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-6">
                 <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Q-Value (Collision)</label>
                    <Select value={rf.q} onChange={e => updateRfPart('q', e.target.value)}>
                        {Array.from({length:16}, (_,i)=>i).map(i=><option key={i} value={i}>{i}</option>)}
                    </Select>
                 </div>
                 <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Session (Persistence)</label>
                    <Select value={rf.session} onChange={e => updateRfPart('session', e.target.value)}>
                        <option value="0">S0 (Immediate)</option><option value="1">S1 (Short)</option>
                        <option value="2">S2 (Long)</option><option value="3">S3 (Extended)</option>
                    </Select>
                 </div>
                 <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Target Flag</label>
                    <Select value={rf.target} onChange={e => updateRfPart('target', e.target.value)}>
                        <option value="0">A (Default)</option><option value="1">B</option><option value="2">A/B (Toggle)</option>
                    </Select>
                 </div>
                 <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Tari / Speed</label>
                    <Select value={rf.speed} onChange={e => updateRfPart('speed', e.target.value)}>
                        <option value="0">Auto</option><option value="1">Fast</option><option value="2">Normal</option><option value="3">Robust</option>
                    </Select>
                 </div>
             </div>
             <p className="mt-6 text-xs text-gray-400 italic">Note: Incorrect baseband settings may significantly reduce read rate. Only change if you understand Gen2 protocol parameters.</p>
        </Card>
    </div>;
};

export default App;

export enum ConnectionStatus {
  DISCONNECTED = 'DISCONNECTED',
  CONNECTING = 'CONNECTING',
  CONNECTED = 'CONNECTED',
  ERROR = 'ERROR'
}

export type ActiveView = 'monitor' | 'find' | 'encoder' | 'settings' | 'batch';

export interface Tag {
  epc: string;
  timestamp: number;
  rssi?: number;
  count: number;
}

export interface Settings {
  power: number;
  frequency: string;
  rfParams: string; // "speed,q,sess,target"
  buzzer: boolean;
  deviceInfo: string;
}

export type LogEntry = {
  type: 'info' | 'error' | 'rx' | 'tx';
  message: string;
  timestamp: number;
};

export type WriteStatus = 'idle' | 'pending' | 'success' | 'error';

