import { ConnectionStatus, ActiveView, Tag, Settings, WriteStatus } from './types';
import { 
  Wifi, Search, Pencil, Settings as SettingsIcon, Rss, 
  Hash, Cpu, LoaderCircle, CheckCircle, XCircle, 
  Battery, Thermometer, ChevronRight, Square, Play, RefreshCw, Trash2, Layers, Download
} from 'lucide-react';
