const FindItemView: React.FC<{onStart:()=>void, onStop:()=>void, isScanning:boolean, targetEpc:string, setTargetEpc:(s:string)=>void, rssi:number|null, lastSeen:number}> =
({onStart, onStop, isScanning, targetEpc, setTargetEpc, rssi, lastSeen}) => {
    const [strength, setStrength] = useState(0);
    useEffect(() => {
        let decayTimer: number;
        if(rssi !== null) {
            setStrength(Math.max(0, Math.min(100, ((rssi + 95) / 60) * 100)));
        }
        const checkDecay = () => {
            if(Date.now() - lastSeen > 2000) setStrength(s => Math.max(0, s-2));
            decayTimer = requestAnimationFrame(checkDecay);
        }
        decayTimer = requestAnimationFrame(checkDecay);
        return () => cancelAnimationFrame(decayTimer);
    }, [rssi, lastSeen]);

    // Removed "h-full flex flex-col justify-center" to fix alignment issues on small screens
    return <div className="max-w-2xl mx-auto py-10 space-y-8">
        <Card className="p-8 md:p-10 flex flex-col items-center gap-8 md:gap-10 text-center shadow-lg border-blue-100/50">
            <div className="space-y-2">
                <h2 className="text-3xl font-bold text-gray-900 tracking-tight">Geiger Search</h2>
                <p className="text-gray-500 font-medium">Pinpoint a specific tag with visual signal feedback.</p>
            </div>

            <div className="w-full max-w-md relative group">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-[#3e6ae1]" size={20}/>
                <input type="text" placeholder="Paste Target EPC..." value={targetEpc} onChange={e => setTargetEpc(e.target.value.toUpperCase())} className="w-full pl-12 pr-4 py-4 bg-gray-50 border border-gray-200 rounded-xl font-mono text-lg focus:ring-2 focus:ring-[#3e6ae1] focus:border-transparent transition-all outline-none text-gray-800 placeholder-gray-400 shadow-inner"/>
            </div>

            <div className="w-full max-w-lg space-y-3">
                 <div className="flex justify-between text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                    <span>Weak</span>
                    <span>Strong</span>
                 </div>
                 <div className="h-14 bg-gray-100 rounded-2xl overflow-hidden p-1.5 shadow-inner ring-1 ring-gray-200/50">
                    <div 
                        className={`h-full rounded-xl transition-all duration-75 ease-linear shadow-lg ${strength > 0 ? 'opacity-100' : 'opacity-30'} ${strength > 70 ? 'bg-gradient-to-r from-emerald-400 to-emerald-500' : strength > 40 ? 'bg-gradient-to-r from-amber-400 to-amber-500' : 'bg-gradient-to-r from-red-400 to-red-500'}`} 
                        style={{width: `${strength}%`}}
                    ></div>
                 </div>
            </div>

            <div className="grid grid-cols-2 gap-6 w-full max-w-sm">
                 <div className="text-center p-5 bg-gray-50 rounded-2xl border border-gray-100">
                    <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold mb-1">Signal (dBm)</p>
                    <p className="text-3xl font-bold text-gray-900">{rssi !== null && strength > 0 ? `${rssi}` : '--'}</p>
                 </div>
                 <div className="text-center p-5 bg-gray-50 rounded-2xl border border-gray-100">
                    <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold mb-1">Status</p>
                    <p className={`text-xl font-bold mt-1 ${strength > 0 ? 'text-green-600' : 'text-gray-400'}`}>
                        {strength > 0 ? 'FOUND' : isScanning ? 'SCANNING' : 'IDLE'}
                    </p>
                 </div>
            </div>

            <div className="w-full max-w-md pt-4">
                 { isScanning ? (
                    <Button variant="danger" onClick={onStop} className="w-full h-14 text-lg font-bold shadow-red-200 hover:shadow-red-300">Stop Search</Button>
                 ) : (
                    <Button variant="primary" onClick={onStart} disabled={!targetEpc} className="w-full h-14 text-lg font-bold shadow-blue-200 hover:shadow-blue-300">Start Finding</Button>
                 )}
            </div>
        </Card>
    </div>;
};

