  </button>
);

const Select: React.FC<React.SelectHTMLAttributes<HTMLSelectElement>> = (props) => (
  <div className="relative">
    <select {...props} className="appearance-none w-full bg-white border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-[#3e6ae1] focus:border-[#3e6ae1] block p-2.5 pr-8 disabled:bg-gray-100 transition-shadow">
      {props.children}
    </select>
    <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-2 text-gray-500">
      <ChevronRight size={16} className="rotate-90"/>
    </div>
  </div>
);

const RangeSlider: React.FC<{ value: number; min: number; max: number; onChange: (val: number) => void }> = ({ value, min, max, onChange }) => (
  <div className="flex items-center gap-4">
    <input 
      type="range" 
      min={min} 
      max={max} 
      value={value} 
      onChange={(e) => onChange(Number(e.target.value))}
