    />
    <div className="min-w-[3ch] text-right font-mono text-sm font-bold text-gray-700">{value}</div>
  </div>
);

// --- MAIN APP ---

function App() {
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [activeView, setActiveView] = useState<ActiveView>('monitor');
  const [isScanning, setIsScanning] = useState(false);

  // Hardware Stats
  const [batteryLevel, setBatteryLevel] = useState(85);
  const [chipTemp, setChipTemp] = useState(42);

  // Settings
  const [settings, setSettings] = useState<Settings>({ 
    power: 30, 
    frequency: 'US', 
    rfParams: '1,4,1,0', // speed,q,session,target
    buzzer: true, 
    deviceInfo: 'ScannerOS v11' 
  });

  const [tags, setTags] = useState<Map<string, Tag>>(new Map());
  const [batchTags, setBatchTags] = useState<Map<string, Tag>>(new Map());
  const [readRate, setReadRate] = useState(0);

  // Feature States
  const [encoderScanTags, setEncoderScanTags] = useState<Tag[]>([]);
  const [isEncoderScanning, setIsEncoderScanning] = useState(false);
  const [writeStatus, setWriteStatus] = useState<WriteStatus>('idle');
  const [writeMessage, setWriteMessage] = useState('');
  const [targetEpc, setTargetEpc] = useState('');
  const [foundTagRssi, setFoundTagRssi] = useState<number | null>(null);
  const [lastRssiUpdate, setLastRssiUpdate] = useState(0);

  const tagsReadInSecond = useRef(0);

  const handleDataReceived = useCallback((data: any) => {
    // 1. Tag Stream
    if (data.cmd === 'live_tags' && Array.isArray(data.tags)) {
      // Determine which state to update based on active view
      const targetSetState = activeView === 'batch' ? setBatchTags : setTags;

      targetSetState(prevTags => {
        const newTags = new Map(prevTags); 
        data.tags.forEach((tag: { e?: string; r?: number }) => {
          if (!tag.e) return;

          tagsReadInSecond.current++;
          const now = Date.now();
          const existing = newTags.get(tag.e);

          if (existing) {
            // Immutable update for React to detect change
            newTags.set(tag.e, {
                ...existing,
                count: existing.count + 1,
                rssi: tag.r,
                timestamp: now
            });
          } else {
            newTags.set(tag.e, { 
                epc: tag.e, 
                timestamp: now, 
                firstSeen: now,
                rssi: tag.r, 
                count: 1 
            });
          }

          if (targetEpc && tag.e === targetEpc) {
            setFoundTagRssi(tag.r ?? null);
            setLastRssiUpdate(now);
          }
        });
        return newTags;
      });
    }

    // 2. Commands & Info
    if (data.cmd === 'DI') setSettings(s => ({ ...s, deviceInfo: data.val }));
    if (data.cmd === 'GP') setSettings(s => ({ ...s, power: data.val }));
    if (data.cmd === 'GF') setSettings(s => ({ ...s, frequency: data.val }));
    if (data.cmd === 'GRP') setSettings(s => ({ ...s, rfParams: data.val }));
    if (data.cmd === 'status') {
      if (data.bat !== undefined) setBatteryLevel(data.bat);
      if (data.temp !== undefined) setChipTemp(data.temp);
    }

    if (data.cmd === 'WE') {
      if (data.status === 'ok') {
        setWriteStatus('success');
        setWriteMessage(`Success! New EPC: ${data.epc}`);
      } else {
        setWriteStatus('error');
        setWriteMessage(data.error || 'Write failed.');
      }
    }
  }, [activeView, targetEpc]);

  useEffect(() => {
    bleService.setCallbacks(handleDataReceived, (msg, type) => {
        // console.log(`[${type}] ${msg}`);
    });

    const rateInterval = setInterval(() => {
      setReadRate(tagsReadInSecond.current);
      tagsReadInSecond.current = 0;
    }, 1000);
    return () => clearInterval(rateInterval);
  }, [handleDataReceived]);

  const handleConnect = async () => {
    try {
      setStatus(ConnectionStatus.CONNECTING);
      await bleService.connect();
      setStatus(ConnectionStatus.CONNECTED);
      setTimeout(() => bleService.getSettings(), 500);
    } catch (e) {
      setStatus(ConnectionStatus.ERROR);
      setTimeout(() => setStatus(ConnectionStatus.DISCONNECTED), 2000);
    }
  };

  const handleDisconnect = () => {
    bleService.disconnect();
    setStatus(ConnectionStatus.DISCONNECTED);
    setIsScanning(false);
    setTags(new Map());
  };

  const handleStartScan = async (mode: 'live' | 'find' | 'encoder' | 'batch') => {
    if (status !== ConnectionStatus.CONNECTED || isScanning) return;
    setIsScanning(true);

    if (mode === 'live') setTags(new Map());
    // Note: Batch mode intentionally does NOT clear tags on start to allow appending, user must clear manually.

    let cmd: object = { cmd: 'S' };
    if (mode === 'find' && targetEpc) cmd = { cmd: 'F', val: targetEpc };
    if (mode === 'batch') cmd = { cmd: 'SB' };

    if (mode === 'encoder') {
      setIsEncoderScanning(true);
      setEncoderScanTags([]);

      const encoderListener = (data: any) => {
        if (data.cmd === 'live_tags' && data.tags) {
          setEncoderScanTags(prev => {
            const newTags = [...prev];
            data.tags.forEach((t: any) => {
              if(!newTags.find(et => et.epc === t.e)) {
                newTags.push({epc: t.e, rssi: t.r, count: 1, timestamp: Date.now(), firstSeen: Date.now()});
              }
            });
            return newTags;
          });
        }
      };

      bleService.setCallbacks(encoderListener, () => {});
      await bleService.sendCommand({ cmd: 'S' });

      setTimeout(async () => {
        await bleService.sendCommand({ cmd: 'X' });
        setIsEncoderScanning(false);
        bleService.setCallbacks(handleDataReceived, () => {});
      }, 3000); 
      return;
    }

    await bleService.sendCommand(cmd);
  };

  const handleStopScan = async (mode?: 'batch') => {
    if (status !== ConnectionStatus.CONNECTED) return;
    const stopCmd = mode === 'batch' ? { cmd: 'XB' } : { cmd: 'X' };
    await bleService.sendCommand(stopCmd);
    setIsScanning(false);
  };

  const handleUpdateSetting = async (key: keyof Settings, value: any) => {
    setSettings(s => ({...s, [key]: value}));
    let cmd = {};
    if (key === 'power') cmd = {cmd: 'SP', val: value};
    if (key === 'frequency') cmd = {cmd: 'SF', val: value};
    if (key === 'buzzer') cmd = {cmd: 'BZ', val: value ? 'on' : 'off'};
    if (key === 'rfParams') cmd = {cmd: 'SRP', val: value};
    await bleService.sendCommand(cmd);
    setTimeout(() => bleService.getSettings(), 200);
  }

  const handleWrite = async (oldEpc: string, newEpc: string) => {
    if (!oldEpc || !newEpc || newEpc.length % 4 !== 0) {
        setWriteStatus('error');
        setWriteMessage('Invalid EPC. Length must be multiple of 4 hex chars.');
        return;
    }
    setWriteStatus('pending');
    setWriteMessage('');
    await bleService.sendCommand({ cmd: 'WE', old: oldEpc, new: newEpc });
    setTimeout(() => { if(writeStatus === 'pending') setWriteStatus('idle'); }, 5000); 
  }

  const sortedTags = useMemo(() => Array.from(tags.values()).sort((a, b) => b.timestamp - a.timestamp), [tags]);
  // Stable sort for Batch View based on insertion time (firstSeen)
  const sortedBatchTags = useMemo(() => Array.from(batchTags.values()).sort((a, b) => b.firstSeen - a.firstSeen), [batchTags]);
  const peakRssi = useMemo(() => sortedTags.length > 0 ? Math.max(...sortedTags.map(t => t.rssi ?? -100)) : '-', [sortedTags]);

  const renderView = () => {
    switch (activeView) {
      case 'monitor': return <LiveMonitorView tags={sortedTags} peakRssi={peakRssi} readRate={readRate} totalTags={tags.size} onClear={() => setTags(new Map())} />;
      case 'find': return <FindItemView onStart={() => handleStartScan('find')} onStop={() => handleStopScan()} isScanning={isScanning} targetEpc={targetEpc} setTargetEpc={setTargetEpc} rssi={foundTagRssi} lastSeen={lastRssiUpdate} />;
      case 'batch': return <BatchView tags={sortedBatchTags} isScanning={isScanning} onStart={() => handleStartScan('batch')} onStop={() => handleStopScan('batch')} onClear={() => setBatchTags(new Map())} />;
      case 'encoder': return <TagEncoderView onScan={() => handleStartScan('encoder')} isScanning={isEncoderScanning} tags={encoderScanTags} onWrite={handleWrite} writeStatus={writeStatus} writeMessage={writeMessage} />;
      case 'settings': return <SettingsView settings={settings} onUpdate={handleUpdateSetting} />;
      default: return null;
    }
  };

  return (
    <div className="fixed inset-0 flex bg-[#f2f4f6] text-gray-900 font-sans">
      <Sidebar activeView={activeView} setActiveView={setActiveView} />
      <main className="flex-1 flex flex-col min-w-0">
        <Header 
          status={status} 
          onConnect={handleConnect} 
          onDisconnect={handleDisconnect} 
          isScanning={isScanning} 
          onStartScan={() => handleStartScan('live')} 
          onStopScan={() => handleStopScan()} 
          activeView={activeView} 
          battery={batteryLevel}
          temp={chipTemp}
        />
        {/* Changed from overflow-hidden to overflow-y-auto to fix scroll issues */}
        <div className="flex-1 overflow-y-auto p-4 md:p-6 relative">
          <div className="max-w-7xl mx-auto h-full">
            {renderView()}
          </div>
        </div>
      </main>
    </div>
  );
}

// --- SUB-COMPONENTS ---

const Sidebar: React.FC<{ activeView: ActiveView; setActiveView: (v: ActiveView) => void }> = ({ activeView, setActiveView }) => {
  const NavItem = ({ icon: Icon, label, view }: { icon: any; label: string; view: ActiveView }) => (
    <button onClick={() => setActiveView(view)} className={`group flex flex-col items-center justify-center gap-1.5 w-full aspect-square rounded-xl transition-all duration-300 ${activeView === view ? 'bg-white text-[#3e6ae1] shadow-md scale-105' : 'text-gray-500 hover:bg-white/60 hover:text-gray-900'}`}>
      <Icon size={24} strokeWidth={activeView === view ? 2.5 : 2} className={`transition-transform duration-300 ${activeView === view ? 'scale-110' : 'group-hover:scale-110'}`} />
      <span className="text-[10px] font-bold tracking-widest uppercase">{label}</span>
    </button>
  );
  return (
    <aside className="w-20 md:w-24 bg-[#f2f4f6] flex flex-col items-center py-6 px-2 gap-3 border-r border-gray-200 z-20 shadow-sm overflow-y-auto no-scrollbar">
      <div className="mb-4"><Logo className="w-10 h-10 text-[#3e6ae1]" /></div>
      <NavItem icon={Rss} label="Monitor" view="monitor" />
      <NavItem icon={Layers} label="Batch" view="batch" />
      <NavItem icon={Search} label="Find" view="find" />
      <NavItem icon={Pencil} label="Encoder" view="encoder" />
      <NavItem icon={SettingsIcon} label="Settings" view="settings" />
    </aside>
  );
};

const Header: React.FC<{ status: ConnectionStatus; onConnect: () => void; onDisconnect: () => void; isScanning: boolean; onStartScan: () => void; onStopScan: () => void, activeView: ActiveView, battery: number, temp: number }> = 
({ status, onConnect, onDisconnect, isScanning, onStartScan, onStopScan, activeView, battery, temp }) => (
  <header className="h-16 md:h-20 bg-white/80 backdrop-blur-md border-b border-gray-200 flex items-center justify-between px-4 md:px-8 z-20 sticky top-0">
    <div className="flex items-center gap-4">
        <h1 className="text-xl md:text-2xl font-bold text-gray-900 capitalize tracking-tight">{activeView === 'monitor' ? 'Live Monitor' : activeView}</h1>
        {status === ConnectionStatus.CONNECTED && <span className="px-2.5 py-1 rounded-full text-[10px] font-bold bg-green-100 text-green-700 tracking-wider ring-1 ring-green-200">ONLINE</span>}
    </div>

    <div className="flex items-center gap-4 md:gap-8">
       {/* Hardware Stats */}
       <div className="hidden md:flex items-center gap-6 text-sm font-semibold text-gray-500">
           <div className="flex items-center gap-2 bg-gray-100 px-3 py-1.5 rounded-lg"><Battery size={18} className={battery < 20 ? 'text-red-500' : 'text-gray-700'} /> <span>{battery}%</span></div>
           <div className="flex items-center gap-2 bg-gray-100 px-3 py-1.5 rounded-lg"><Thermometer size={18} className="text-gray-700" /> <span>{temp}°C</span></div>
       </div>

       <div className="h-8 w-px bg-gray-300 hidden md:block"></div>

      {/* Controls */}
      <div className="flex items-center gap-2 md:gap-3">
        {activeView === 'monitor' && status === ConnectionStatus.CONNECTED && (
            isScanning 
            ? <Button variant="danger" onClick={onStopScan} className="h-9 md:h-10 px-4 md:px-6 shadow-red-200 shadow-lg"><Square size={16} fill="currentColor"/> Stop</Button> 
            : <Button variant="primary" onClick={onStartScan} className="h-9 md:h-10 px-4 md:px-6 shadow-blue-200 shadow-lg"><Play size={16} fill="currentColor"/> Start</Button>
        )}
        <Button variant={status === ConnectionStatus.CONNECTED ? "secondary" : "primary"} onClick={status === ConnectionStatus.CONNECTED ? onDisconnect : onConnect} disabled={status === ConnectionStatus.CONNECTING} className="h-9 md:h-10 px-4 md:px-6">
            {status === ConnectionStatus.CONNECTING ? <LoaderCircle size={18} className="animate-spin"/> : status === ConnectionStatus.CONNECTED ? 'Disconnect' : 'Connect Device'}
        </Button>
      </div>
    </div>
  </header>
);

const LiveMonitorView: React.FC<{ tags: Tag[], totalTags: number, readRate: number, peakRssi: number | string, onClear: () => void }> = ({ tags, totalTags, readRate, peakRssi, onClear }) => {
    return (
    <div className="flex flex-col h-full gap-6">
        {/* HUD */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 md:gap-6">
            <Card className="p-6 flex flex-row items-center justify-between !overflow-hidden">
                 <div><p className="text-gray-500 text-xs font-bold uppercase tracking-wider mb-1">Total Tags</p><p className="text-3xl md:text-4xl font-bold text-gray-900">{totalTags}</p></div>
                 <div className="w-12 h-12 rounded-full bg-blue-50 flex items-center justify-center text-[#3e6ae1]"><Hash size={24} /></div>
            </Card>
            <Card className="p-6 flex flex-row items-center justify-between !overflow-hidden">
                 <div><p className="text-gray-500 text-xs font-bold uppercase tracking-wider mb-1">Read Rate</p><p className="text-3xl md:text-4xl font-bold text-gray-900">{readRate} <span className="text-lg font-medium text-gray-400">t/s</span></p></div>
                 <div className="w-12 h-12 rounded-full bg-orange-50 flex items-center justify-center text-orange-500"><Cpu size={24} /></div>
            </Card>
             <Card className="p-6 flex flex-row items-center justify-between !overflow-hidden">
                 <div><p className="text-gray-500 text-xs font-bold uppercase tracking-wider mb-1">Peak RSSI</p><p className="text-3xl md:text-4xl font-bold text-gray-900">{peakRssi} <span className="text-lg font-medium text-gray-400">dBm</span></p></div>
                 <div className="w-12 h-12 rounded-full bg-green-50 flex items-center justify-center text-green-600"><Wifi size={24} /></div>
            </Card>
        </div>

        {/* TABLE */}
        <Card className="flex-1 flex flex-col p-0 border-gray-200 overflow-hidden shadow-sm min-h-[400px]">
             <div className="px-6 py-4 border-b border-gray-100 flex justify-between items-center bg-gray-50">
                 <h3 className="font-bold text-gray-800">Scanned Data</h3>
                 <button onClick={onClear} className="text-xs font-semibold text-gray-500 hover:text-red-500 flex items-center gap-1 uppercase tracking-wide"><Trash2 size={14}/> Clear List</button>
             </div>

             <div className="flex-1 overflow-auto">
                <table className="w-full text-left border-collapse">
                    <thead className="bg-gray-50 sticky top-0 z-10 shadow-sm">
                        <tr>
                            <th className="px-6 py-3 text-xs font-bold text-gray-500 uppercase tracking-wider whitespace-nowrap">#</th>
                            <th className="px-6 py-3 text-xs font-bold text-gray-500 uppercase tracking-wider w-full">EPC</th>
                            <th className="px-6 py-3 text-xs font-bold text-gray-500 uppercase tracking-wider whitespace-nowrap hidden sm:table-cell">Signal</th>
                            <th className="px-6 py-3 text-xs font-bold text-gray-500 uppercase tracking-wider text-right whitespace-nowrap">dBm</th>
                            <th className="px-6 py-3 text-xs font-bold text-gray-500 uppercase tracking-wider text-right whitespace-nowrap hidden sm:table-cell">Time</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                        {tags.length === 0 ? (
                            <tr><td colSpan={5} className="px-6 py-12 text-center text-gray-400">No tags detected. Press Start to scan.</td></tr>
                        ) : (
                            tags.map((tag, idx) => {
                                const rssiPercent = tag.rssi ? Math.max(0, Math.min(100, ((tag.rssi + 90) / 60) * 100)) : 0;
                                let colorClass = 'bg-red-500';
                                if (rssiPercent > 70) colorClass = 'bg-emerald-500';
                                else if (rssiPercent > 40) colorClass = 'bg-amber-500';

                                return (
                                    <tr key={tag.epc} className="hover:bg-blue-50/30 transition-colors group">
                                        <td className="px-6 py-3 text-gray-400 font-mono text-xs whitespace-nowrap">{tags.length - idx}</td>
                                        <td className="px-6 py-3 font-mono text-gray-800 font-medium group-hover:text-[#3e6ae1] transition-colors cursor-pointer select-all break-all" title="Click to copy">{tag.epc}</td>
                                        <td className="px-6 py-3 hidden sm:table-cell">
                                            <div className="w-24 bg-gray-200 rounded-full h-1.5 overflow-hidden">
                                                <div className={`h-full rounded-full transition-all duration-300 ${colorClass}`} style={{width: `${rssiPercent}%`}}></div>
                                            </div>
                                        </td>
                                        <td className="px-6 py-3 text-right font-mono text-gray-700 font-semibold whitespace-nowrap">{tag.rssi}</td>
                                        <td className="px-6 py-3 text-right text-gray-400 text-xs font-medium whitespace-nowrap hidden sm:table-cell">{new Date(tag.timestamp).toLocaleTimeString()}</td>
                                    </tr>
                                );
                            })
                        )}
                    </tbody>
                </table>
             </div>
        </Card>
    </div>
    );
};

const BatchView: React.FC<{ tags: Tag[], isScanning: boolean, onStart: () => void, onStop: () => void, onClear: () => void }> = ({ tags, isScanning, onStart, onStop, onClear }) => {
  const exportCsv = () => {
    const csvContent = "data:text/csv;charset=utf-8," + 
      "EPC,RSSI,Count,LastSeen\n" + 
      tags.map(t => `${t.epc},${t.rssi},${t.count},${new Date(t.timestamp).toISOString()}`).join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `scan_batch_${new Date().getTime()}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const totalReads = tags.reduce((acc, t) => acc + t.count, 0);

  return <div className="flex flex-col h-full gap-6">
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
      <Card className="col-span-1 md:col-span-2 lg:col-span-3 p-6 flex items-center justify-between !overflow-hidden">
        <div>
           <h2 className="text-xl font-bold text-gray-900">Batch Inventory</h2>
           <p className="text-sm text-gray-500 mt-1">Scan items in bulk and export results.</p>
        </div>
        <div className="flex gap-3">
           {isScanning ? (
              <Button variant="danger" onClick={onStop} className="h-10 px-6 font-bold shadow-lg"><Square size={16} fill="currentColor"/> Stop & Save</Button>
           ) : (
              <Button variant="primary" onClick={onStart} className="h-10 px-6 font-bold shadow-lg"><Play size={16} fill="currentColor"/> Start Batch</Button>
           )}
        </div>
      </Card>
      <Card className="col-span-1 p-6 flex flex-col justify-center">
         <p className="text-xs font-bold text-gray-500 uppercase tracking-widest">Unique Items</p>
         <p className="text-4xl font-bold text-gray-900 mt-2">{tags.length}</p>
         <p className="text-xs text-gray-400 mt-1">Total Reads: {totalReads}</p>
      </Card>
    </div>

    <Card className="flex-1 flex flex-col p-0 border-gray-200 overflow-hidden shadow-sm min-h-[400px]">
       <div className="px-6 py-4 border-b border-gray-100 flex justify-between items-center bg-gray-50">
          <h3 className="font-bold text-gray-800">Batch Results</h3>
          <div className="flex gap-3">
             <button onClick={onClear} className="text-xs font-semibold text-gray-500 hover:text-red-500 flex items-center gap-1 uppercase tracking-wide"><Trash2 size={14}/> Clear</button>
             <div className="h-4 w-px bg-gray-300"></div>
             <button onClick={exportCsv} disabled={tags.length === 0} className="text-xs font-semibold text-[#3e6ae1] hover:text-blue-700 flex items-center gap-1 uppercase tracking-wide disabled:opacity-50"><Download size={14}/> Export CSV</button>
          </div>
       </div>
       <div className="flex-1 overflow-auto">
          <table className="w-full text-left border-collapse">
              <thead className="bg-gray-50 sticky top-0 z-10 shadow-sm">
                  <tr>
                      <th className="px-6 py-3 text-xs font-bold text-gray-500 uppercase tracking-wider w-16">#</th>
                      <th className="px-6 py-3 text-xs font-bold text-gray-500 uppercase tracking-wider">EPC</th>
                      <th className="px-6 py-3 text-xs font-bold text-gray-500 uppercase tracking-wider text-right">Count</th>
                      <th className="px-6 py-3 text-xs font-bold text-gray-500 uppercase tracking-wider text-right hidden sm:table-cell">Last Seen</th>
                  </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                  {tags.length === 0 ? (
                      <tr><td colSpan={4} className="px-6 py-12 text-center text-gray-400">Ready to scan.</td></tr>
                  ) : (
                      tags.map((tag, idx) => (
                          <tr key={tag.epc} className="hover:bg-blue-50/30 transition-colors">
                              <td className="px-6 py-3 text-gray-400 font-mono text-xs">{idx + 1}</td>
                              <td className="px-6 py-3 font-mono text-gray-800 font-medium select-all break-all">{tag.epc}</td>
                              <td className="px-6 py-3 text-right font-mono text-gray-700 font-semibold">{tag.count}</td>
                              <td className="px-6 py-3 text-right text-gray-400 text-xs hidden sm:table-cell">{new Date(tag.timestamp).toLocaleTimeString()}</td>
                          </tr>
                      ))
                  )}
              </tbody>
          </table>
       </div>
    </Card>
  </div>;
};

const FindItemView: React.FC<{onStart:()=>void, onStop:()=>void, isScanning:boolean, targetEpc:string, setTargetEpc:(s:string)=>void, rssi:number|null, lastSeen:number}> =
({onStart, onStop, isScanning, targetEpc, setTargetEpc, rssi, lastSeen}) => {
    const [strength, setStrength] = useState(0);
    useEffect(() => {
        let decayTimer: number;
        if(rssi !== null) {
            setStrength(Math.max(0, Math.min(100, ((rssi + 95) / 60) * 100)));
        }
        const checkDecay = () => {
            if(Date.now() - lastSeen > 2000) setStrength(s => Math.max(0, s-2));
            decayTimer = requestAnimationFrame(checkDecay);
        }
        decayTimer = requestAnimationFrame(checkDecay);
        return () => cancelAnimationFrame(decayTimer);
    }, [rssi, lastSeen]);

    // Removed "h-full flex flex-col justify-center" to fix alignment issues on small screens
    return <div className="max-w-2xl mx-auto py-10 space-y-8">
        <Card className="p-8 md:p-10 flex flex-col items-center gap-8 md:gap-10 text-center shadow-lg border-blue-100/50">
            <div className="space-y-2">
                <h2 className="text-3xl font-bold text-gray-900 tracking-tight">Geiger Search</h2>
                <p className="text-gray-500 font-medium">Pinpoint a specific tag with visual signal feedback.</p>
            </div>

            <div className="w-full max-w-md relative group">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-[#3e6ae1]" size={20}/>
                <input type="text" placeholder="Paste Target EPC..." value={targetEpc} onChange={e => setTargetEpc(e.target.value.toUpperCase())} className="w-full pl-12 pr-4 py-4 bg-gray-50 border border-gray-200 rounded-xl font-mono text-lg focus:ring-2 focus:ring-[#3e6ae1] focus:border-transparent transition-all outline-none text-gray-800 placeholder-gray-400 shadow-inner"/>
            </div>

            <div className="w-full max-w-lg space-y-3">
                 <div className="flex justify-between text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                    <span>Weak</span>
                    <span>Strong</span>
                 </div>
                 <div className="h-14 bg-gray-100 rounded-2xl overflow-hidden p-1.5 shadow-inner ring-1 ring-gray-200/50">
                    <div 
                        className={`h-full rounded-xl transition-all duration-75 ease-linear shadow-lg ${strength > 0 ? 'opacity-100' : 'opacity-30'} ${strength > 70 ? 'bg-gradient-to-r from-emerald-400 to-emerald-500' : strength > 40 ? 'bg-gradient-to-r from-amber-400 to-amber-500' : 'bg-gradient-to-r from-red-400 to-red-500'}`} 
                        style={{width: `${strength}%`}}
                    ></div>
                 </div>
            </div>

            <div className="grid grid-cols-2 gap-6 w-full max-w-sm">
                 <div className="text-center p-5 bg-gray-50 rounded-2xl border border-gray-100">
                    <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold mb-1">Signal (dBm)</p>
                    <p className="text-3xl font-bold text-gray-900">{rssi !== null && strength > 0 ? `${rssi}` : '--'}</p>
                 </div>
                 <div className="text-center p-5 bg-gray-50 rounded-2xl border border-gray-100">
                    <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold mb-1">Status</p>
                    <p className={`text-xl font-bold mt-1 ${strength > 0 ? 'text-green-600' : 'text-gray-400'}`}>
                        {strength > 0 ? 'FOUND' : isScanning ? 'SCANNING' : 'IDLE'}
                    </p>
                 </div>
            </div>

            <div className="w-full max-w-md pt-4">
                 { isScanning ? (
                    <Button variant="danger" onClick={onStop} className="w-full h-14 text-lg font-bold shadow-red-200 hover:shadow-red-300">Stop Search</Button>
                 ) : (
                    <Button variant="primary" onClick={onStart} disabled={!targetEpc} className="w-full h-14 text-lg font-bold shadow-blue-200 hover:shadow-blue-300">Start Finding</Button>
                 )}
            </div>
        </Card>
    </div>;
};

const TagEncoderView: React.FC<{onScan:()=>void, isScanning:boolean, tags:Tag[], onWrite:(old:string,neu:string)=>void, writeStatus:WriteStatus, writeMessage:string}> =
({onScan, isScanning, tags, onWrite, writeStatus, writeMessage}) => {
    const [currentEpc, setCurrentEpc] = useState('');
    const [newEpc, setNewEpc] = useState('');

    return <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-full max-w-7xl mx-auto py-4">
        <Card title="1. Select Source Tag" className="flex flex-col h-full border-blue-100" action={<Button variant="secondary" onClick={onScan} disabled={isScanning} className="text-xs font-semibold">{isScanning ? <LoaderCircle className="animate-spin" size={14}/> : 'Scan Nearby (3s)'}</Button>}>
            <div className="flex-1 overflow-y-auto min-h-[300px] -mx-6 px-6">
                {tags.length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center text-gray-300 space-y-4">
                        <Search size={64} className="opacity-20"/>
                        <p className="font-medium">No nearby tags found yet.</p>
                    </div>
                ) : (
                    <div className="space-y-2 py-2">
                         {tags.map(t => (
                            <div key={t.epc} onClick={() => setCurrentEpc(t.epc)} className={`px-4 py-3 rounded-xl border cursor-pointer transition-all flex items-center justify-between group ${currentEpc === t.epc ? 'bg-blue-50 border-[#3e6ae1] shadow-sm ring-1 ring-[#3e6ae1]' : 'bg-white border-gray-100 hover:border-blue-200 hover:bg-gray-50'}`}>
                                <div className="flex items-center gap-3">
                                    <div className={`w-2 h-2 rounded-full ${currentEpc === t.epc ? 'bg-[#3e6ae1]' : 'bg-gray-300'}`}></div>
                                    <span className="font-mono text-sm font-medium text-gray-700">{t.epc}</span>
                                </div>
                                <span className={`text-xs font-bold ${t.rssi && t.rssi > -60 ? 'text-green-600' : 'text-gray-400'}`}>{t.rssi} dBm</span>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </Card>
        <Card title="2. Write New Data" className="h-fit border-orange-100">
             <div className="space-y-8 py-2">
                <div>
                    <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Target Tag (Old EPC)</label>
                    <div className="relative">
                        <input readOnly value={currentEpc} placeholder="Select a tag from the left..." className="w-full p-4 bg-gray-50 border border-gray-200 rounded-xl font-mono text-gray-500 focus:outline-none transition-all"/>
                        {currentEpc && <CheckCircle size={20} className="absolute right-4 top-1/2 -translate-y-1/2 text-green-500"/>}
                    </div>
                </div>
                <div>
                    <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">New Data (New EPC)</label>
                    <input value={newEpc} onChange={e=>setNewEpc(e.target.value.toUpperCase())} maxLength={24} placeholder="Enter 24 Hex Characters..." className="w-full p-4 bg-white border border-gray-300 rounded-xl font-mono text-gray-900 focus:ring-2 focus:ring-[#3e6ae1] focus:border-transparent transition-all outline-none"/>
                    <div className="flex justify-between mt-2 px-1">
                        <small className="text-red-400 font-medium">{newEpc.length % 4 !== 0 ? 'Length must be multiple of 4' : ''}</small>
                        <small className="text-gray-400 font-medium">{newEpc.length}/24 chars</small>
                    </div>
                </div>

                <div className="pt-6 border-t border-gray-100">
                     <Button variant="primary" onClick={() => onWrite(currentEpc, newEpc)} disabled={!currentEpc || newEpc.length % 4 !== 0 || writeStatus === 'pending'} className="w-full h-14 text-base font-bold shadow-lg shadow-blue-100 hover:shadow-blue-200">
                        {writeStatus === 'pending' ? <><LoaderCircle className="animate-spin"/> Writing...</> : 'Write to Tag'}
                     </Button>
                     {writeMessage && (
                        <div className={`mt-4 p-4 rounded-xl flex items-center gap-3 text-sm font-semibold animate-in fade-in slide-in-from-top-2 ${writeStatus === 'success' ? 'bg-green-50 text-green-700 border border-green-100' : 'bg-red-50 text-red-700 border border-red-100'}`}>
                            {writeStatus === 'success' ? <CheckCircle size={20}/> : <XCircle size={20}/>}
                            {writeMessage}
                        </div>
                     )}
                </div>
             </div>
        </Card>
    </div>;
};

const SettingsView: React.FC<{ settings: Settings; onUpdate: (key: keyof Settings, value: any) => void }> = ({ settings, onUpdate }) => {
    // Local State for "Apply" Logic
    const [local, setLocal] = useState(settings);

    useEffect(() => { setLocal(settings); }, [settings]);

    const parseRf = (str: string) => {
        const parts = str.split(',');
        return { 
            speed: parts[0] || '1', 
            q: parts[1] || '4', 
            session: parts[2] || '1', 
            target: parts[3] || '0' 
        };
    };

    const rf = useMemo(() => parseRf(local.rfParams), [local.rfParams]);

    // Check Dirty States
    const isConfigDirty = local.power !== settings.power || local.frequency !== settings.frequency || local.buzzer !== settings.buzzer;
    const isBasebandDirty = local.rfParams !== settings.rfParams;

    // Helpers
    const updateRfPart = (key: 'speed'|'q'|'session'|'target', val: string) => {
        const current = parseRf(local.rfParams);
        const next = { ...current, [key]: val };
        const nextStr = `${next.speed},${next.q},${next.session},${next.target}`;
        setLocal(s => ({ ...s, rfParams: nextStr }));
    };

    const handleApplyConfig = () => {
        if (local.power !== settings.power) onUpdate('power', local.power);
        if (local.frequency !== settings.frequency) onUpdate('frequency', local.frequency);
        if (local.buzzer !== settings.buzzer) onUpdate('buzzer', local.buzzer);
    };

    return <div className="max-w-5xl mx-auto space-y-8 pb-10 py-4">

        {/* Device Info */}
        <Card title="System Information">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                 <div><p className="text-xs text-gray-400 uppercase tracking-widest font-bold mb-1">Model Name</p><p className="font-mono text-lg font-semibold text-gray-900">Nextwaves Scanner V3</p></div>
                 <div><p className="text-xs text-gray-400 uppercase tracking-widest font-bold mb-1">Firmware Version</p><p className="font-mono text-lg font-semibold text-gray-900">{settings.deviceInfo}</p></div>
             </div>
        </Card>

        {/* General Configuration */}
        <Card 
            title="Radio Configuration" 
            action={isConfigDirty && <Button variant="primary" onClick={handleApplyConfig} className="text-xs h-9">Apply Changes</Button>}
        >
            <div className="space-y-8">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-8 items-center border-b border-gray-100 pb-8">
                    <label className="text-sm font-semibold text-gray-700">RF Output Power</label>
                    <div className="md:col-span-2">
                        <RangeSlider min={0} max={33} value={local.power} onChange={v => setLocal(s => ({...s, power: v}))} />
                        <p className="text-xs text-gray-400 mt-2">Higher power increases range but consumes more battery.</p>
                    </div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-8 items-center border-b border-gray-100 pb-8">
                    <label className="text-sm font-semibold text-gray-700">Frequency Region</label>
                    <div className="md:col-span-2">
                        <Select value={local.frequency} onChange={e => setLocal(s => ({...s, frequency: e.target.value}))}>
                            <option value="US">FCC (United States) 902-928 MHz</option>
                            <option value="EU">ETSI (Europe) 865-868 MHz</option>
                            <option value="CN">China 920-925 MHz</option>
                        </Select>
                    </div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-8 items-center">
                    <label className="text-sm font-semibold text-gray-700">System Buzzer</label>
                    <div className="md:col-span-2 flex items-center gap-4">
                        <Toggle checked={local.buzzer} onChange={v => setLocal(s => ({...s, buzzer: v}))}/>
                        <span className="text-sm text-gray-600 font-medium">{local.buzzer ? 'Enabled' : 'Muted'}</span>
                    </div>
                </div>
            </div>
        </Card>

        {/* Baseband Configuration */}
        <Card 
            title="Advanced Baseband" 
            action={isBasebandDirty && <Button variant="primary" onClick={() => onUpdate('rfParams', local.rfParams)} className="text-xs h-9">Apply Config</Button>}
        >
             <div className="grid grid-cols-1 md:grid-cols-2 gap-x-12 gap-y-8">
                 <div>
                    <label className="block text-xs font-bold text-gray-400 uppercase tracking-widest mb-3">Q-Value (Collision)</label>
                    <Select value={rf.q} onChange={e => updateRfPart('q', e.target.value)}>
                        <option value="4">4 (Standard)</option>
                        <option value="0">0 (Single Tag)</option>
                        <option value="6">6 (High Density)</option>
                        <option value="10">10 (Extreme)</option>
                    </Select>
                 </div>
                 <div>
                    <label className="block text-xs font-bold text-gray-400 uppercase tracking-widest mb-3">Session (Persistence)</label>
                    <Select value={rf.session} onChange={e => updateRfPart('session', e.target.value)}>
                        <option value="0">S0 (Immediate)</option><option value="1">S1 (Short)</option>
                        <option value="2">S2 (Long)</option><option value="3">S3 (Extended)</option>
                    </Select>
                 </div>
                 <div>
                    <label className="block text-xs font-bold text-gray-400 uppercase tracking-widest mb-3">Target Flag</label>
                    <Select value={rf.target} onChange={e => updateRfPart('target', e.target.value)}>
                        <option value="0">A (Default)</option><option value="1">B</option><option value="2">A/B (Toggle)</option>
                    </Select>
                 </div>
                 <div>
                    <label className="block text-xs font-bold text-gray-400 uppercase tracking-widest mb-3">Tari / Speed</label>
                    <Select value={rf.speed} onChange={e => updateRfPart('speed', e.target.value)}>
                        <option value="0">Auto</option><option value="1">Fast</option><option value="2">Normal</option><option value="3">Robust</option>
                    </Select>
                 </div>
             </div>
             <div className="mt-8 p-4 bg-blue-50 rounded-xl border border-blue-100 text-blue-800 text-xs flex items-start gap-3">
                <div className="bg-blue-200 p-1 rounded-full"><RefreshCw size={12}/></div>
                <p>Incorrect baseband settings may significantly reduce read rate. Only change if you understand Gen2 protocol parameters.</p>
             </div>
        </Card>
    </div>;
};

export default App;
